"use client"

import { Suspense, useState, useCallback, useEffect } from "react"
import { useSearchParams } from "next/navigation"
import { motion } from "framer-motion"
import type { City } from "@/src/cities/domain/city.entity"
import type { FictionWithMedia } from "@/src/fictions/domain/fiction.entity"
import type { Location } from "@/src/locations/domain/location.entity"
import { MapView, Map3DToggleSlot, MapMinimapSlot } from "@/components/map/map-view"
import { MapProvider } from "@/lib/map"
import { CitySelector } from "@/components/map/city-selector"
import { FictionSelector } from "@/components/map/fiction-selector"
import { LocationDetail } from "@/components/map/location-detail"
import { ThumbnailCarousel } from "@/components/map/thumbnail-carousel"
import { usePlaceSelectorCollapsedStorage } from "@/lib/local-storage-service-hooks"
import { useRouter } from "@/i18n/navigation"
import {
  getAllCitiesAction,
  getCityFictionsAction,
} from "@/src/cities/infrastructure/next/city.actions"
import { getPlaceLocationAction, getPlacesInBboxAction } from "@/src/places/infrastructure/next/place.actions"
import { isUuidString } from "@/lib/validation/primitives"

type Bbox = { west: number; south: number; east: number; north: number }

/** Returns a bbox (west, south, east, north) for a ~radiusKm square around lat/lng. */
function bboxAround(lat: number, lng: number, radiusKm: number): Bbox {
  const kmPerDegLat = 111.32
  const deltaLat = radiusKm / kmPerDegLat
  const deltaLng = radiusKm / (kmPerDegLat * Math.cos((lat * Math.PI) / 180))
  return {
    west: lng - deltaLng,
    south: lat - deltaLat,
    east: lng + deltaLng,
    north: lat + deltaLat,
  }
}

/** Union of two bboxes so the result contains both areas. */
function bboxUnion(a: Bbox, b: Bbox): Bbox {
  return {
    west: Math.min(a.west, b.west),
    south: Math.min(a.south, b.south),
    east: Math.max(a.east, b.east),
    north: Math.max(a.north, b.north),
  }
}

const MIN_LOAD_RADIUS_KM = 50

function MapPageInner() {
  const router = useRouter()
  const searchParams = useSearchParams()
  const initialFictionId = searchParams.get("fiction")
  const initialCityId = searchParams.get("city")
  const placeParam = searchParams.get("place")
  const [placeSelectorCollapsed, setPlaceSelectorCollapsed] = usePlaceSelectorCollapsedStorage()

  const [cities, setCities] = useState<City[]>([])
  const [selectedCity, setSelectedCity] = useState<City | null>(null)
  const [availableFictions, setAvailableFictions] = useState<FictionWithMedia[]>([])
  const [selectedFictionIds, setSelectedFictionIds] = useState<string[]>([])
  const [filteredLocations, setFilteredLocations] = useState<Location[]>([])
  const [selectedLocation, setSelectedLocation] = useState<Location | null>(null)
  const [focusedLocationId, setFocusedLocationId] = useState<string | null>(null)
  const [is3D, setIs3D] = useState(false)
  const [mapLoaded, setMapLoaded] = useState(false)
  const [bounds, setBounds] = useState<{ west: number; south: number; east: number; north: number } | null>(null)
  const [citiesLoading, setCitiesLoading] = useState(true)

  // Load cities, then open city/fictions (optionally from ?city= & ?fiction= when opening from a fiction page)
  useEffect(() => {
    setCitiesLoading(true)
    getAllCitiesAction()
      .then((citiesList: City[]) => {
        setCities(citiesList)
        if (citiesList.length === 0) return
        const city =
          (initialCityId && citiesList.find((c) => c.id === initialCityId)) || citiesList[0]
        setSelectedCity(city)
        return getCityFictionsAction(city.id).then((fics: FictionWithMedia[]) => {
          setAvailableFictions(fics)
          if (initialFictionId && fics.some((f) => f.id === initialFictionId)) {
            setSelectedFictionIds([initialFictionId])
          } else {
            setSelectedFictionIds(fics.map((f) => f.id))
          }
        })
      })
      .catch(() => {})
      .finally(() => setCitiesLoading(false))
    // Intentionally only on mount; query is read once for initial state.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  // Deep link ?place=: sync focus and ensure the pin is in the list (bbox query can omit it or SSR had no searchParams).
  useEffect(() => {
    if (placeParam && isUuidString(placeParam)) {
      setFocusedLocationId(placeParam)
    }
  }, [placeParam])

  useEffect(() => {
    if (!selectedCity || selectedFictionIds.length === 0) {
      setFilteredLocations([])
      return
    }
    const minBbox = bboxAround(selectedCity.lat, selectedCity.lng, MIN_LOAD_RADIUS_KM)
    const bbox = bounds ? bboxUnion(bounds, minBbox) : minBbox
    const deepPlaceId = placeParam && isUuidString(placeParam) ? placeParam : null
    let cancelled = false
    getPlacesInBboxAction(selectedFictionIds, bbox)
      .then(async (data) => {
        if (cancelled) return
        let list = data ?? []
        if (deepPlaceId && !list.some((l) => l.id === deepPlaceId)) {
          const loc = await getPlaceLocationAction(deepPlaceId)
          if (cancelled) return
          if (loc) list = [...list, loc]
        }
        if (!cancelled) setFilteredLocations(list)
      })
      .catch(() => {})
    return () => {
      cancelled = true
    }
  }, [selectedCity?.id, selectedCity?.lat, selectedCity?.lng, selectedFictionIds, bounds, placeParam])

  const handleCityChange = useCallback(async (city: City) => {
    setSelectedCity(city)
    setSelectedLocation(null)
    setFocusedLocationId(null)
    const fics = await getCityFictionsAction(city.id)
    setAvailableFictions(fics)
    setSelectedFictionIds(fics.map((f) => f.id))
  }, [])

  const handleToggleFiction = (fictionId: string) => {
    setSelectedFictionIds((prev) =>
      prev.includes(fictionId) ? prev.filter((id) => id !== fictionId) : [...prev, fictionId],
    )
    setSelectedLocation(null)
    setFocusedLocationId(null)
  }

  const handleLocationClick = useCallback((location: Location) => {
    setSelectedLocation(location)
    setFocusedLocationId(location.id)
  }, [])

  /** Navigate map to place (from carousel) without opening sidebar. */
  const handleNavigateToPlace = useCallback((location: Location) => {
    setFocusedLocationId(location.id)
  }, [])

  const handleExplorePlace = useCallback(
    (location: Location) => {
      setSelectedLocation(null)
      router.push(
        `/fiction/${encodeURIComponent(location.fictionId)}/place/${encodeURIComponent(location.id)}`,
      )
    },
    [router],
  )

  const isNavigationModeActive = !placeSelectorCollapsed && filteredLocations.length > 0

  useEffect(() => {
    if (!isNavigationModeActive) return
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target
      const isHTMLElement = target instanceof HTMLElement
      const isInputLike =
        isHTMLElement &&
        (target.tagName === "INPUT" ||
          target.tagName === "TEXTAREA" ||
          target.getAttribute("contenteditable") === "true")

      if (e.key === "Enter" || e.key === " ") {
        if (isInputLike) return
        if (focusedLocationId && !selectedLocation) {
          const loc = filteredLocations.find((l) => l.id === focusedLocationId)
          if (loc) {
            e.preventDefault()
            setSelectedLocation(loc)
          }
        }
      } else if (e.key === "Escape") {
        e.preventDefault()
        if (selectedLocation) {
          setSelectedLocation(null)
        } else {
          setPlaceSelectorCollapsed(true)
        }
      }
    }
    window.addEventListener("keydown", handleKeyDown)
    return () => window.removeEventListener("keydown", handleKeyDown)
  }, [
    isNavigationModeActive,
    focusedLocationId,
    selectedLocation,
    filteredLocations,
    setPlaceSelectorCollapsed,
  ])

  return (
    <MapProvider>
      {citiesLoading || !selectedCity ? (
        <div className="flex min-h-full items-center justify-center bg-background">
          <p className="text-muted-foreground">Loading map…</p>
        </div>
      ) : (
      <div className="absolute inset-0 min-h-0 flex flex-col">
      <motion.div
        className="absolute left-4 top-4 z-[1000] flex items-center gap-2"
        initial={{ opacity: 0, y: -12 }}
        animate={
          mapLoaded
            ? { opacity: 1, y: 0 }
            : { opacity: 0, y: -12 }
        }
        transition={{ duration: 0.35, ease: "easeOut" }}
      >
        <FictionSelector
          availableFictions={availableFictions}
          selectedFictionIds={selectedFictionIds}
          onToggleFiction={handleToggleFiction}
        />
      </motion.div>

      <motion.div
        className="absolute right-4 top-4 z-[1000] flex items-center gap-2"
        initial={{ opacity: 0, y: -12 }}
        animate={
          mapLoaded
            ? { opacity: 1, y: 0 }
            : { opacity: 0, y: -12 }
        }
        transition={{ duration: 0.35, ease: "easeOut", delay: 0.08 }}
      >
        <Map3DToggleSlot />
        <CitySelector
          cities={cities}
          selectedCity={selectedCity}
          onCityChange={handleCityChange}
        />
      </motion.div>

      <div className="relative flex-1 min-h-0 w-full">
        <MapView
          city={selectedCity}
          locations={filteredLocations}
          onLocationClick={handleLocationClick}
          selectedLocationId={selectedLocation?.id}
          focusLocationId={focusedLocationId}
          is3D={is3D}
          onToggle3D={setIs3D}
          onMapLoaded={() => setMapLoaded(true)}
          onBoundsChange={setBounds}
        />
      </div>

      <MapMinimapSlot />

      <ThumbnailCarousel
        locations={filteredLocations}
        selectedLocationId={focusedLocationId ?? selectedLocation?.id}
        onLocationClick={handleNavigateToPlace}
        placeSelectorCollapsed={placeSelectorCollapsed}
        setPlaceSelectorCollapsed={setPlaceSelectorCollapsed}
      />

      {selectedLocation && (
        <LocationDetail
          location={selectedLocation}
          fiction={availableFictions.find((f) => f.id === selectedLocation.fictionId)}
          onClose={() => setSelectedLocation(null)}
          onViewPlace={handleExplorePlace}
        />
      )}

      </div>
      )}
    </MapProvider>
  )
}

export default function MapPage() {
  return (
    <Suspense
      fallback={
        <div className="flex min-h-full items-center justify-center bg-background">
          <p className="text-muted-foreground">Loading map…</p>
        </div>
      }
    >
      <MapPageInner />
    </Suspense>
  )
}

"use client"

import { useEffect, useState } from "react"
import { useRouter } from "@/i18n/navigation"
import { Input } from "@/components/ui/input"
import { Button } from "@/components/ui/button"
import { createClient } from "@/lib/supabase/client"
import { cn } from "@/lib/utils"

interface UsernameFormProps {
  userId: string
  userEmail: string
  userName?: string | null
}

export function UsernameForm({ userId, userEmail, userName }: UsernameFormProps) {
  const router = useRouter()
  const [username, setUsername] = useState("")
  const [error, setError] = useState<string | null>(null)
  const [available, setAvailable] = useState<boolean | null>(null)
  const [checking, setChecking] = useState(false)
  const [submitting, setSubmitting] = useState(false)
  const [skipNextDebounce, setSkipNextDebounce] = useState(false)

  // Suggest an initial username from the email and ensure it's available.
  useEffect(() => {
    if (username.trim().length > 0) return

    const emailLocalPart = userEmail?.split("@")[0]?.trim() ?? ""
    if (!emailLocalPart) return

    let cancelled = false

    const suggestUsername = async () => {
      const supabase = createClient()
      const base = emailLocalPart.replace(/[^a-zA-Z0-9.-]/g, "")

      const { data: isBaseAvailable, error: baseError } = await supabase.rpc("check_username_available", {
        p_username: base,
      })

      if (cancelled) return

      if (!baseError && isBaseAvailable === true) {
        setUsername(base)
        setAvailable(true)
        setSkipNextDebounce(true)
        return
      }

      const randomSuffix = Math.floor(100 + Math.random() * 900)
      const withSuffix = `${base}-${randomSuffix}`
      const { data: isSuffixAvailable } = await supabase.rpc("check_username_available", {
        p_username: withSuffix,
      })

      if (cancelled) return

      setUsername(withSuffix)
      setAvailable(isSuffixAvailable === true)
      if (isSuffixAvailable === false) {
        setError("This username is already taken")
      }
      setSkipNextDebounce(true)
    }

    void suggestUsername()

    return () => {
      cancelled = true
    }
  }, [userEmail, username])

  const validateUsername = (value: string) => {
    const trimmed = value.trim()
    if (trimmed.length < 3) return "Username must be at least 3 characters"
    if (!/^[a-zA-Z0-9.-]+$/.test(trimmed)) {
      return "Only letters, numbers, dots (.) and hyphens (-) are allowed"
    }
    return null
  }

  const checkAvailability = async (value: string) => {
    const trimmed = value.trim()
    if (validateUsername(trimmed)) {
      setAvailable(null)
      return
    }
    setChecking(true)
    setError(null)
    try {
      const supabase = createClient()
      const { data: isAvailable, error: rpcError } = await supabase.rpc("check_username_available", {
        p_username: trimmed,
      })
      if (rpcError) {
        setError("Could not check availability. You can still continue.")
        setAvailable(null)
        return
      }
      setAvailable(isAvailable === true)
      if (isAvailable === false) setError("This username is already taken")
    } finally {
      setChecking(false)
    }
  }

  // Debounced availability check after user stops typing.
  useEffect(() => {
    if (skipNextDebounce) {
      setSkipNextDebounce(false)
      return
    }

    const trimmed = username.trim()
    if (!trimmed) {
      setAvailable(null)
      return
    }

    const handle = setTimeout(() => {
      void checkAvailability(trimmed)
    }, 500)

    return () => clearTimeout(handle)
  }, [username])

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()

    const validationError = validateUsername(username)
    if (validationError) {
      setError(validationError)
      return
    }

    setSubmitting(true)
    setError(null)

    try {
      const supabase = createClient()
      const { data: isAvailable, error: checkError } = await supabase.rpc("check_username_available", {
        p_username: username.trim(),
      })
      if (!checkError && isAvailable === false) {
        setError("This username is already taken")
        setAvailable(false)
        return
      }

      const { error: updateError } = await supabase
        .from("profiles")
        .update({
          username: username.trim(),
          full_name: userName?.trim() || null,
        })
        .eq("id", userId)

      if (updateError) {
        if (updateError.code === "23505") {
          setError("This username is already taken")
        } else {
          setError("Could not save username. Please try again.")
        }
        return
      }

      router.replace("/onboarding")
    } finally {
      setSubmitting(false)
    }
  }

  return (
    <div className="flex min-h-screen w-full items-center justify-center bg-background px-4">
      <div className="w-full max-w-md rounded-2xl border border-border bg-card p-8 shadow-sm">
        <h1 className="text-2xl font-bold text-foreground">Choose your username</h1>
        <p className="mt-2 text-sm text-muted-foreground">
          This will be your public name in FiktionMaps. You can change it later in your profile
          settings.
        </p>

        <form onSubmit={handleSubmit} className="mt-6 space-y-4">
          <div>
            <label className="mb-1 block text-sm font-medium text-foreground">Username</label>
            <div className="relative">
              <Input
                type="text"
                value={username}
                onChange={(e) => {
                  setUsername(e.target.value)
                  setError(null)
                  setAvailable(null)
                }}
                placeholder="your_username"
                className={cn(
                  "h-11 pr-28",
                  error
                    ? "border-destructive focus-visible:ring-destructive/30"
                    : available === true
                    ? "border-emerald-500 text-emerald-600 focus-visible:ring-emerald-500/30"
                    : ""
                )}
                autoFocus
              />
              {checking && (
                <span className="pointer-events-none absolute inset-y-0 right-3 flex items-center text-xs font-medium text-muted-foreground">
                  Checking…
                </span>
              )}
              {!checking && available === true && !error && (
                <span className="pointer-events-none absolute inset-y-0 right-3 flex items-center text-xs font-medium text-emerald-500">
                  Looks great
                </span>
              )}
            </div>
            <div className="mt-1 min-h-[1.5rem] text-xs space-y-0.5">
              <p className="text-muted-foreground">
                Letters, numbers, dots (.) and hyphens (-). Min 3 characters.
              </p>
              {error && <p className="text-destructive">{error}</p>}
            </div>
          </div>

          <Button
            type="submit"
            className={cn("h-11 w-full font-semibold")}
            disabled={submitting || !!validateUsername(username)}
          >
            {submitting ? "Saving…" : "Continue"}
          </Button>
        </form>
      </div>
    </div>
  )
}

"use client"

import { useState, useEffect } from "react"
import { useSearchParams } from "next/navigation"
import { Book, MapPin, Clapperboard, Building2, LayoutGrid, List, Users } from "lucide-react"
import { cn } from "@/lib/utils"
import { FictionsTab } from "./fictions-tab"
import { CitiesTab } from "./cities-tab"
import { LocationsTab } from "./locations-tab"
import { ScenesTab } from "./scenes-tab"
import { PersonsTab } from "./persons-tab"
import type { Fiction } from "@/src/fictions/domain/fiction.entity"
import type { City } from "@/src/cities/domain/city.entity"
import type { Location } from "@/src/locations/domain/location.entity"
import type { Person } from "@/src/persons/domain/person.entity"
import { useAdminViewModeStorage } from "@/lib/local-storage-service-hooks"

type AdminSection = "fictions" | "cities" | "locations" | "scenes" | "persons"

interface SectionItem {
  id: AdminSection
  label: string
  description: string
  icon: React.ElementType
  color: string
}

const sections: SectionItem[] = [
  {
    id: "fictions",
    label: "Manage Fictions",
    description: "Create and edit fictional stories, movies, and series",
    icon: Book,
    color: "from-foreground/80 to-foreground/60",
  },
  {
    id: "cities",
    label: "Manage Cities",
    description: "Create and edit cities for map views",
    icon: Building2,
    color: "from-blue-600 to-cyan-600",
  },
  {
    id: "locations",
    label: "Manage Places",
    description: "Create places by picking real locations on the map and linking them to fictions",
    icon: MapPin,
    color: "from-purple-600 to-pink-600",
  },
  {
    id: "scenes",
    label: "Manage Scenes",
    description: "Organize scenes within fictions and link them to locations",
    icon: Clapperboard,
    color: "from-orange-600 to-red-600",
  },
  {
    id: "persons",
    label: "Manage People",
    description: "Create and manage authors, directors, actors, and other people",
    icon: Users,
    color: "from-teal-600 to-emerald-600",
  },
]

interface AdminDashboardProps {
  initialFictions?: Fiction[]
  initialCities?: City[]
  initialLocations?: Location[]
  initialPersons?: Person[]
  onOpenFiction?: (fictionId: string) => void
  onOpenCity?: (cityId: string) => void
}

export function AdminDashboard({ initialFictions, initialCities, initialLocations, initialPersons, onOpenFiction, onOpenCity }: AdminDashboardProps) {
  const searchParams = useSearchParams()
  const [activeSection, setActiveSection] = useState<AdminSection>(() => {
    const tab = searchParams.get("tab")
    return (sections.some((s) => s.id === tab) ? tab : "fictions") as AdminSection
  })

  const [viewMode, setViewMode] = useAdminViewModeStorage()

  useEffect(() => {
    const tab = searchParams.get("tab")
    if (tab && sections.some((s) => s.id === tab)) {
      setActiveSection(tab as AdminSection)
    }
  }, [searchParams])

  return (
    <div className="flex h-full min-h-0 w-full flex-col bg-gradient-to-b from-background to-background/50">
      {/* Header — sticky within the centered column (same canvas rhythm as profile) */}
      <div className="sticky top-0 z-40 border-b border-border bg-card/50 py-6 backdrop-blur-sm">
        <h1 className="text-3xl font-extrabold tracking-tight text-foreground">
          Content Management
        </h1>
        <p className="text-sm text-muted-foreground mt-1">
          Edit and manage fictions, cities, locations, and scenes
        </p>
      </div>

      {/* Tabs bar */}
      <div className="border-b border-border bg-card/30">
        <div className="flex items-center justify-between gap-4">
          <nav className="flex gap-0" aria-label="Admin sections">
            {sections.map((section) => {
              const Icon = section.icon
              const isActive = activeSection === section.id
              return (
                <button
                  key={section.id}
                  onClick={() => setActiveSection(section.id)}
                  aria-selected={isActive}
                  role="tab"
                  className={cn(
                    "flex items-center gap-2 px-5 py-4 text-sm font-medium transition-colors border-b-2 -mb-px",
                    isActive
                      ? "border-foreground text-foreground"
                      : "border-transparent text-muted-foreground hover:text-foreground hover:border-border",
                  )}
                >
                  <Icon className="h-4 w-4 shrink-0" />
                  {section.label.replace("Manage ", "")}
                </button>
              )
            })}
          </nav>
          <div
            className="flex rounded-lg border border-border bg-card p-0.5"
            role="tablist"
            aria-label="View mode"
          >
            <button
              type="button"
              onClick={() => setViewMode("cards")}
              aria-selected={viewMode === "cards"}
              aria-label="Cards view"
              className={cn(
                "flex items-center justify-center p-2 rounded-md transition-colors",
                viewMode === "cards"
                  ? "bg-foreground text-background"
                  : "text-muted-foreground hover:text-foreground",
              )}
              title="Cards view"
            >
              <LayoutGrid className="h-4 w-4" />
            </button>
            <button
              type="button"
              onClick={() => setViewMode("table")}
              aria-selected={viewMode === "table"}
              aria-label="Table view"
              className={cn(
                "flex items-center justify-center p-2 rounded-md transition-colors",
                viewMode === "table"
                  ? "bg-foreground text-background"
                  : "text-muted-foreground hover:text-foreground",
              )}
              title="Table view"
            >
              <List className="h-4 w-4" />
            </button>
          </div>
        </div>
      </div>

      {/* Main content */}
      <div className="min-h-0 flex-1 overflow-y-auto">
        <div className="w-full pb-10 pt-6">
          {activeSection === "fictions" && (
            <FictionsTab
              initialFictions={initialFictions}
              onOpenFiction={onOpenFiction}
              viewMode={viewMode}
            />
          )}
          {activeSection === "cities" && (
            <CitiesTab
              initialCities={initialCities}
              onOpenCity={onOpenCity}
              viewMode={viewMode}
            />
          )}
          {activeSection === "locations" && <LocationsTab initialLocations={initialLocations} initialFictions={initialFictions} initialCities={initialCities} />}
          {activeSection === "scenes" && <ScenesTab initialFictions={initialFictions} initialPlaces={initialLocations} />}
          {activeSection === "persons" && <PersonsTab initialPersons={initialPersons} viewMode={viewMode} />}
        </div>
      </div>
    </div>
  )
}

"use client"

import { useEffect, useState } from "react"
import { useRouter } from "@/i18n/navigation"
import { ArrowLeft, ArrowRight, Plus, MoreVertical, Edit2, Trash2, MapPin, Search, Loader2 } from "lucide-react"
import type { City } from "@/src/cities/domain/city.entity"
import { Button } from "@/components/ui/button"
import { createCityAction, deleteCityAction } from "@/src/cities/infrastructure/next/city.actions"
import {
  AlertDialog,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import { CityMapPicker } from "./city-map-picker"
import { MapProvider, MapContainer } from "@/lib/map"

interface CityFormData {
  name: string
  country: string
  lat: string
  lng: string
  zoom: string
}

type ViewMode = "cards" | "table"

interface CitiesTabProps {
  initialCities?: City[]
  onOpenCity?: (cityId: string) => void
  viewMode?: ViewMode
}

export function CitiesTab({ initialCities, onOpenCity, viewMode = "cards" }: CitiesTabProps) {
  const router = useRouter()
  const [cities, setCities] = useState<City[]>(initialCities ?? [])
  const [showWizard, setShowWizard] = useState(false)
  const [wizardStep, setWizardStep] = useState(0)
  const [searchTerm, setSearchTerm] = useState("")
  const [formData, setFormData] = useState<CityFormData>(() => ({
    name: "",
    country: "",
    lat: "48.8566",
    lng: "2.3522",
    zoom: "10",
  }))
  const [errors, setErrors] = useState<Record<string, string>>({})
  const [submitError, setSubmitError] = useState<string | null>(null)
  const [submitting, setSubmitting] = useState(false)
  const [cityToDelete, setCityToDelete] = useState<City | null>(null)
  const [deleteConfirmName, setDeleteConfirmName] = useState("")
  const [deleting, setDeleting] = useState(false)

  useEffect(() => {
    setCities(initialCities ?? [])
  }, [initialCities])

  const defaultCenter = { lat: 48.8566, lng: 2.3522 }
  const resetForm = () =>
    setFormData({
      name: "",
      country: "",
      lat: String(defaultCenter.lat),
      lng: String(defaultCenter.lng),
      zoom: "10",
    })

  const openWizard = () => {
    resetForm()
    setErrors({})
    setWizardStep(0)
    setShowWizard(true)
  }

  const closeWizard = () => {
    setShowWizard(false)
    setWizardStep(0)
    setErrors({})
  }

  const validateForm = (): boolean => {
    const newErrors: Record<string, string> = {}
    if (!formData.name.trim()) newErrors.name = "Name is required"
    if (!formData.country.trim()) newErrors.country = "Country is required"
    const lat = parseFloat(formData.lat)
    const lng = parseFloat(formData.lng)
    const zoom = parseInt(formData.zoom, 10)
    if (Number.isNaN(lat) || lat < -90 || lat > 90) newErrors.lat = "Latitude must be -90 to 90"
    if (Number.isNaN(lng) || lng < -180 || lng > 180) newErrors.lng = "Longitude must be -180 to 180"
    if (Number.isNaN(zoom) || zoom < 0 || zoom > 22) newErrors.zoom = "Zoom must be 0–22"
    setErrors(newErrors)
    return Object.keys(newErrors).length === 0
  }

  const doCreate = async () => {
    setSubmitError(null)
    if (!validateForm()) return
    setSubmitting(true)
    const fd = new FormData()
    fd.set("name", formData.name.trim())
    fd.set("country", formData.country.trim())
    fd.set("lat", formData.lat)
    fd.set("lng", formData.lng)
    fd.set("zoom", formData.zoom)
    const result = await createCityAction(fd)
    setSubmitting(false)
    if (result.success) {
      closeWizard()
      resetForm()
      setCities((prev) => [...prev, result.city].sort((a, b) => a.name.localeCompare(b.name)))
      router.refresh()
      if (result.city.id && onOpenCity) onOpenCity(result.city.id)
    } else {
      setSubmitError(result.error)
    }
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    doCreate()
  }

  const filteredCities = cities.filter(
    (city) =>
      city.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      city.country.toLowerCase().includes(searchTerm.toLowerCase())
  )

  const openCity = (id: string) => {
    if (onOpenCity) onOpenCity(id)
    else router.push(`/admin/city/${id}`)
  }

  const openDeleteModal = (e: React.MouseEvent, city: City) => {
    e.stopPropagation()
    setCityToDelete(city)
    setDeleteConfirmName("")
  }

  const closeDeleteModal = () => {
    setCityToDelete(null)
    setDeleteConfirmName("")
  }

  const handleConfirmDelete = async () => {
    if (!cityToDelete || deleteConfirmName !== cityToDelete.name) return
    setDeleting(true)
    const result = await deleteCityAction(cityToDelete.id)
    setDeleting(false)
    if (result.success) {
      closeDeleteModal()
      setCities((prev) => prev.filter((c) => c.id !== cityToDelete.id))
      router.refresh()
    }
  }

  const deleteNameMatches = cityToDelete !== null && deleteConfirmName === cityToDelete.name

  if (showWizard) {
    const citySelected = !!formData.name
    return (
      <>
        <div className="fixed inset-0 bottom-[70px] md:bottom-0 md:left-[60px] z-[3000] bg-background flex flex-col overflow-y-auto">
          {/* Header */}
          <div className="px-4 sm:px-6 pt-6 pb-4 flex items-start justify-between gap-4">
            <div>
              <button
                type="button"
                onClick={wizardStep === 0 ? closeWizard : () => setWizardStep(0)}
                className="inline-flex items-center gap-2 text-sm text-muted-foreground hover:text-foreground transition-colors mb-3"
              >
                <ArrowLeft className="h-4 w-4" />
                {wizardStep === 0 ? "Back to Cities" : "Back to map"}
              </button>
              <h2 className="text-2xl font-bold text-foreground">Create City</h2>
              <p className="text-sm text-muted-foreground mt-1">
                {wizardStep === 0 ? "Search for a city and position it on the map." : "Review the details before saving."}
              </p>
            </div>
            <span className="mt-1 text-sm font-medium text-muted-foreground shrink-0">
              Step {wizardStep + 1} of 2
            </span>
          </div>

          <form onSubmit={handleSubmit} className="flex flex-col w-full flex-1 min-h-0">
            {/* Step 1 — map (keep mounted so state persists; hidden in step 2) */}
            <div className={wizardStep === 1 ? "hidden" : "flex flex-col w-full flex-1 min-h-0"}>
              <CityMapPicker
                mapKeySuffix="create"
                center={
                  formData.lat && formData.lng
                    ? { lat: parseFloat(formData.lat), lng: parseFloat(formData.lng) }
                    : defaultCenter
                }
                zoom={formData.zoom ? parseInt(formData.zoom, 10) : 10}
                onCenterChange={(lat, lng) =>
                  setFormData((prev) => ({ ...prev, lat: String(lat), lng: String(lng) }))
                }
                onZoomChange={(zoom) => setFormData((prev) => ({ ...prev, zoom: String(zoom) }))}
                onCitySelect={(_, __, name, country) =>
                  setFormData((prev) => ({ ...prev, name, country }))
                }
                onClear={() => setFormData((prev) => ({ ...prev, name: "", country: "" }))}
                cityName={formData.name}
                cityCountry={formData.country}
                introMode
                showSearch
                onError={(msg) => setErrors((prev) => ({ ...prev, map: msg }))}
              />
            </div>

            {/* Step 2 — summary */}
            {wizardStep === 1 && (
              <div className="flex flex-col flex-1 items-center px-4 sm:px-6 py-8 pb-28">
                <div className="w-full max-w-2xl space-y-6">
                  {/* Map preview */}
                  <div className="w-full h-80 rounded-2xl overflow-hidden border border-border">
                    <MapProvider libraries={[]}>
                      <MapContainer
                        id="city-summary-map"
                        mapKey="city-summary-preview"
                        defaultCenter={{ lat: parseFloat(formData.lat), lng: parseFloat(formData.lng) }}
                        defaultZoom={parseInt(formData.zoom, 10)}
                        className="h-full w-full"
                        interactive={false}
                        controls={{ zoom: false }}
                      />
                    </MapProvider>
                  </div>

                  {/* City name & country */}
                  <div className="text-center space-y-1">
                    <p className="text-3xl font-black tracking-tight text-foreground">{formData.name}</p>
                    <p className="text-base text-muted-foreground">{formData.country}</p>
                  </div>

                  {/* Coordinates table */}
                  <div className="divide-y divide-border rounded-xl border border-border overflow-hidden">
                    <div className="flex items-center justify-between px-6 py-4 bg-card">
                      <span className="text-sm text-muted-foreground">Latitude</span>
                      <span className="font-mono text-sm text-foreground">{parseFloat(formData.lat).toFixed(5)}</span>
                    </div>
                    <div className="flex items-center justify-between px-6 py-4 bg-card">
                      <span className="text-sm text-muted-foreground">Longitude</span>
                      <span className="font-mono text-sm text-foreground">{parseFloat(formData.lng).toFixed(5)}</span>
                    </div>
                    <div className="flex items-center justify-between px-6 py-4 bg-card">
                      <span className="text-sm text-muted-foreground">Zoom</span>
                      <span className="font-mono text-sm text-foreground">{formData.zoom}</span>
                    </div>
                  </div>

                  {submitError && (
                    <p className="text-sm text-red-500 bg-red-500/10 border border-red-500/30 rounded-lg px-4 py-2">
                      {submitError}
                    </p>
                  )}
                </div>
              </div>
            )}
          </form>
        </div>

        {/* Fixed bottom bar — step 1 */}
        {wizardStep === 0 && (
          <div className="fixed bottom-[70px] left-0 right-0 md:bottom-0 md:left-[60px] z-[3001] border-t border-border bg-background px-4 sm:px-6 py-4">
            <div className="flex items-center justify-between gap-4">
              <Button type="button" variant="outline" onClick={closeWizard} className="rounded-xl px-6">
                <ArrowLeft className="h-4 w-4 mr-2" />
                Back
              </Button>
              <Button
                type="button"
                variant="cta"
                disabled={!citySelected}
                onClick={() => setWizardStep(1)}
                className="rounded-xl gap-2 px-6"
              >
                Next
                <ArrowRight className="h-4 w-4" />
              </Button>
            </div>
          </div>
        )}

        {/* Fixed bottom bar — step 2 submit */}
        {wizardStep === 1 && (
          <div className="fixed bottom-[70px] left-0 right-0 md:bottom-0 md:left-[60px] z-[3001] border-t border-border bg-background px-4 sm:px-6 py-4">
            <div className="flex items-center justify-between gap-4">
              <Button type="button" variant="outline" onClick={() => setWizardStep(0)} className="rounded-xl px-6 shrink-0">
                <ArrowLeft className="h-4 w-4 mr-2" />
                Edit
              </Button>
              <div className="min-w-0 text-center">
                <p className="text-sm font-semibold text-foreground truncate">{formData.name}</p>
                <p className="text-xs text-muted-foreground truncate">{formData.country}</p>
              </div>
              <Button
                type="button"
                variant="cta"
                className="gap-2 rounded-xl px-6 shrink-0"
                disabled={submitting}
                onClick={doCreate}
              >
                {submitting ? (
                  <>
                    <Loader2 className="h-4 w-4 animate-spin" />
                    Creating…
                  </>
                ) : (
                  "Create City"
                )}
              </Button>
            </div>
          </div>
        )}
      </>
    )
  }

  return (
    <div className="space-y-6">
      <div className="space-y-3">
        <div className="flex items-start justify-between gap-4">
          <div>
            <h2 className="text-lg font-bold text-foreground flex items-center gap-2">
              <MapPin className="h-5 w-5" />
              Cities ({filteredCities.length})
            </h2>
            <p className="text-xs text-muted-foreground mt-1">
              Manage cities for map views and locations.
            </p>
          </div>
          <Button onClick={openWizard} variant="cta" className="gap-2">
            <Plus className="h-4 w-4" />
            Create City
          </Button>
        </div>
        <div className="flex flex-wrap items-center gap-3">
          <div className="relative flex-1 min-w-[200px]">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <input
              type="text"
              placeholder="Search cities..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 rounded-lg border border-border bg-card text-foreground placeholder:text-muted-foreground focus:outline-none focus:border-foreground transition-colors"
            />
          </div>
        </div>
      </div>

      {viewMode === "cards" ? (
        <div className="max-w-6xl">
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {filteredCities.map((city) => (
              <div
                key={city.id}
                role="button"
                tabIndex={0}
                onClick={() => openCity(city.id)}
                onKeyDown={(e) => {
                  if (e.key === "Enter" || e.key === " ") {
                    e.preventDefault()
                    openCity(city.id)
                  }
                }}
                className="group rounded-xl border border-border hover:border-foreground/30 hover:bg-card/50 transition-all overflow-hidden"
              >
                <div className="p-4 space-y-3">
                  <div className="flex items-start justify-between gap-2">
                    <div className="flex-1 min-w-0">
                      <h3 className="font-semibold text-foreground truncate text-base">{city.name}</h3>
                      <p className="text-xs text-muted-foreground mt-1">{city.country}</p>
                      <p className="text-xs text-muted-foreground mt-0.5">
                        {city.lat.toFixed(4)}, {city.lng.toFixed(4)} · zoom {city.zoom}
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center justify-end opacity-0 group-hover:opacity-100 transition-opacity">
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <button
                          type="button"
                          onClick={(e) => e.stopPropagation()}
                          className="p-2 rounded-lg text-muted-foreground hover:bg-foreground/10 hover:text-foreground transition-colors"
                          aria-label="Actions"
                        >
                          <MoreVertical className="h-4 w-4" />
                        </button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end" onClick={(e) => e.stopPropagation()}>
                        <DropdownMenuItem
                          onClick={(e) => {
                            e.stopPropagation()
                            openCity(city.id)
                          }}
                        >
                          <Edit2 className="h-3 w-3" />
                          Edit
                        </DropdownMenuItem>
                        <DropdownMenuItem
                          onClick={(e) => openDeleteModal(e as React.MouseEvent, city)}
                          className="text-red-600 focus:text-red-600"
                        >
                          <Trash2 className="h-3 w-3" />
                          Delete
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      ) : (
        <div className="w-full overflow-x-auto rounded-xl border border-border">
          <table className="w-full border-collapse text-left">
            <thead>
              <tr className="border-b border-border bg-muted/40">
                <th className="text-xs font-semibold uppercase text-muted-foreground py-3 px-4 text-left">Name</th>
                <th className="text-xs font-semibold uppercase text-muted-foreground py-3 px-4 text-left">Country</th>
                <th className="text-xs font-semibold uppercase text-muted-foreground py-3 px-4 text-left">Lat</th>
                <th className="text-xs font-semibold uppercase text-muted-foreground py-3 px-4 text-left">Lng</th>
                <th className="text-xs font-semibold uppercase text-muted-foreground py-3 px-4 text-left">Zoom</th>
                <th className="text-xs font-semibold uppercase text-muted-foreground py-3 px-4 text-left w-20">Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredCities.map((city) => (
                <tr
                  key={city.id}
                  role="button"
                  tabIndex={0}
                  onClick={() => openCity(city.id)}
                  onKeyDown={(e) => {
                    if (e.key === "Enter" || e.key === " ") {
                      e.preventDefault()
                      openCity(city.id)
                    }
                  }}
                  className="border-b border-border hover:bg-card/50 transition-colors last:border-b-0"
                >
                  <td className="py-3 px-4 text-left font-medium text-foreground">{city.name}</td>
                  <td className="py-3 px-4 text-left text-sm text-muted-foreground">{city.country}</td>
                  <td className="py-3 px-4 text-left text-sm text-muted-foreground">{city.lat.toFixed(4)}</td>
                  <td className="py-3 px-4 text-left text-sm text-muted-foreground">{city.lng.toFixed(4)}</td>
                  <td className="py-3 px-4 text-left text-sm text-muted-foreground">{city.zoom}</td>
                  <td className="py-3 px-4 text-left" onClick={(e) => e.stopPropagation()}>
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <button
                          type="button"
                          className="p-2 rounded-lg text-muted-foreground hover:bg-foreground/10 hover:text-foreground transition-colors"
                          aria-label="Actions"
                        >
                          <MoreVertical className="h-4 w-4" />
                        </button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuItem onClick={() => openCity(city.id)}>
                          <Edit2 className="h-3 w-3" />
                          Edit
                        </DropdownMenuItem>
                        <DropdownMenuItem
                          onClick={(e) => openDeleteModal(e as React.MouseEvent, city)}
                          className="text-red-600 focus:text-red-600"
                        >
                          <Trash2 className="h-3 w-3" />
                          Delete
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      <AlertDialog open={cityToDelete !== null} onOpenChange={(open) => { if (!open) closeDeleteModal() }}>
        <AlertDialogContent onClick={(e) => e.stopPropagation()}>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete city</AlertDialogTitle>
            <AlertDialogDescription>
              This action cannot be undone. To confirm, type the exact name of the city to delete.
              {cityToDelete && (
                <span className="mt-2 block font-semibold text-foreground">«{cityToDelete.name}»</span>
              )}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <div className="py-2">
            <input
              type="text"
              value={deleteConfirmName}
              onChange={(e) => setDeleteConfirmName(e.target.value)}
              placeholder="Exact name of the city"
              className="w-full px-4 py-2 rounded-lg border border-border bg-card text-foreground placeholder:text-muted-foreground focus:outline-none focus:border-foreground focus:ring-1 focus:ring-foreground/20"
              autoFocus
            />
          </div>
          <AlertDialogFooter>
            <AlertDialogCancel onClick={closeDeleteModal}>Cancel</AlertDialogCancel>
            <Button
              variant="destructive"
              disabled={!deleteNameMatches || deleting}
              onClick={handleConfirmDelete}
            >
              {deleting ? (
                <>
                  <Loader2 className="h-4 w-4 animate-spin" />
                  Deleting…
                </>
              ) : (
                "Delete"
              )}
            </Button>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  )
}

"use client"

import { type ReactNode, useCallback, useEffect, useRef, useState } from "react"
import { Search, X } from "lucide-react"
import { MapProvider, MapContainer } from "@/lib/map"
import type { MapControlHandle } from "@/lib/map/types"
import { cn } from "@/lib/utils"
import { MAPBOX_ACCESS_TOKEN } from "@/lib/map/mapbox/styles"

const CITY_MAP_ID = "admin-city-map"
const BASE_URL = "https://api.mapbox.com/geocoding/v5/mapbox.places"
const DEFAULT_CENTER = { lat: 48.8566, lng: 2.3522 }
const INTRO_CENTER = { lat: 20, lng: 0 }
const DEFAULT_ZOOM = 10
const MIN_ZOOM = 0
const MAX_ZOOM = 22

const INTRO_FLY_DURATION = 2000
const CITY_FLY_DURATION = 2500

interface MapboxPlaceFeature {
  id: string
  text: string
  place_name: string
  center: [number, number]
  context?: Array<{ id: string; text: string }>
}

export interface CityMapPickerProps {
  center: { lat: number; lng: number }
  zoom: number
  onCenterChange: (lat: number, lng: number) => void
  onZoomChange: (zoom: number) => void
  onCitySelect?: (lat: number, lng: number, name: string, country: string) => void
  /** Called when the user clears the search input */
  onClear?: () => void
  showSearch?: boolean
  onError?: (message: string) => void
  className?: string
  mapKeySuffix?: string
  cityName?: string
  cityCountry?: string
  /** When true: starts at zoom 0, spins the globe, then flies to selected city */
  introMode?: boolean
  /** When provided, shows a Next button inline with the search input */
  onNext?: () => void
  /** Rendered as an absolute overlay inside the map container */
  mapOverlay?: ReactNode
}

function CityMapSync({
  zoom,
  flyToTarget,
  clearFlyToTarget,
  mapControlRef,
  mapReady,
  blocked,
}: {
  zoom: number
  flyToTarget: { lat: number; lng: number } | null
  clearFlyToTarget: () => void
  mapControlRef: React.MutableRefObject<MapControlHandle | null>
  mapReady: boolean
  blocked: boolean
}) {
  useEffect(() => {
    if (!mapReady || blocked) return
    const ctrl = mapControlRef.current
    if (!ctrl) return
    ctrl.setZoom(zoom)
  }, [mapReady, zoom, mapControlRef, blocked])

  useEffect(() => {
    if (!flyToTarget || !mapReady || blocked) return
    const target = { ...flyToTarget }
    const tryMove = () => {
      const ctrl = mapControlRef.current
      if (!ctrl) return false
      try {
        ctrl.flyTo({ center: target, zoom, duration: 1200 })
        setTimeout(clearFlyToTarget, 1400)
        return true
      } catch {
        return false
      }
    }
    if (tryMove()) return
    const id = setInterval(tryMove, 100)
    const t = setTimeout(() => clearInterval(id), 6000)
    return () => { clearInterval(id); clearTimeout(t) }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [flyToTarget?.lat, flyToTarget?.lng, zoom, mapReady, mapControlRef, blocked])
  return null
}

function CitySearch({
  onSelect,
  onError,
  onClear,
}: {
  onSelect: (lat: number, lng: number, name: string, country: string) => void
  onError?: (message: string) => void
  onClear?: () => void
}) {
  const [value, setValue] = useState("")
  const [loading, setLoading] = useState(false)
  const [predictions, setPredictions] = useState<MapboxPlaceFeature[]>([])

  const searchCities = useCallback(async (input: string) => {
    if (!MAPBOX_ACCESS_TOKEN || input.trim().length < 2) {
      setPredictions([])
      return
    }
    try {
      const params = new URLSearchParams({
        access_token: MAPBOX_ACCESS_TOKEN,
        autocomplete: "true",
        types: "place",
        limit: "5",
        language: "en",
      })
      const res = await fetch(`${BASE_URL}/${encodeURIComponent(input)}.json?${params}`)
      if (!res.ok) return
      const data = await res.json()
      setPredictions((data.features ?? []) as MapboxPlaceFeature[])
    } catch {
      setPredictions([])
    }
  }, [])

  const handleClear = useCallback(() => {
    setValue("")
    setPredictions([])
    onError?.("")
    onClear?.()
  }, [onError, onClear])

  const handleInputChange = useCallback(
    (nextValue: string) => {
      setValue(nextValue)
      onError?.("")
      if (!nextValue.trim()) {
        setPredictions([])
        onClear?.()
        return
      }
      searchCities(nextValue)
    },
    [onError, searchCities, onClear],
  )

  const parseNameAndCountry = useCallback((feature: MapboxPlaceFeature) => {
    const name = feature.text || feature.place_name?.split(",")[0]?.trim() || ""
    const countryContext = feature.context?.find((c) => c.id.startsWith("country."))
    const country = countryContext?.text || feature.place_name?.split(",").pop()?.trim() || ""
    return { name, country }
  }, [])

  const handleSelect = useCallback(
    (feature: MapboxPlaceFeature) => {
      const [lng, lat] = feature.center
      const { name, country } = parseNameAndCountry(feature)
      onSelect(lat, lng, name, country)
      setValue(feature.place_name)
      setPredictions([])
      onError?.("")
    },
    [onSelect, onError, parseNameAndCountry],
  )

  const handleGeocode = useCallback(async () => {
    if (!value.trim()) { onError?.("Enter a city name to search."); return }
    if (!MAPBOX_ACCESS_TOKEN) { onError?.("Map not ready."); return }
    setLoading(true)
    try {
      const params = new URLSearchParams({ access_token: MAPBOX_ACCESS_TOKEN, types: "place", limit: "1", language: "en" })
      const res = await fetch(`${BASE_URL}/${encodeURIComponent(value)}.json?${params}`)
      if (!res.ok) { onError?.("Could not find that city."); return }
      const data = await res.json()
      const feature = data.features?.[0] as MapboxPlaceFeature | undefined
      if (!feature) { onError?.("No city found. Try another name."); return }
      handleSelect(feature)
    } catch {
      onError?.("Search failed. Try again.")
    } finally {
      setLoading(false)
    }
  }, [value, onError, handleSelect])

  return (
    <div className="relative w-full">
      <div className="relative">
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground pointer-events-none" />
        <input
          type="text"
          value={value}
          onChange={(e) => handleInputChange(e.target.value)}
          onKeyDown={(e) => { if (e.key === "Enter") { e.preventDefault(); handleGeocode() } }}
          placeholder="Search city (e.g. London, Paris)"
          autoComplete="off"
          className="w-full pl-12 pr-10 py-4 text-base border-t-0 border-b border-x-0 border-border rounded-none bg-background text-foreground placeholder:text-muted-foreground focus:outline-none focus:border-foreground/40 transition-colors"
        />
        {value && (
          <button
            type="button"
            onMouseDown={(e) => e.preventDefault()}
            onClick={handleClear}
            className="absolute right-4 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
          >
            <X className="h-4 w-4" />
          </button>
        )}
      </div>

      {predictions.length > 0 && (
        <div className="absolute top-full left-0 right-0 z-50 border-b border-x-0 border-border bg-background overflow-hidden">
          {predictions.map((feature) => (
            <button
              key={feature.id}
              type="button"
              onMouseDown={(e) => e.preventDefault()}
              onClick={() => handleSelect(feature)}
              className="w-full text-left px-4 py-3 text-sm text-foreground hover:bg-muted transition-colors border-t border-border"
            >
              {feature.place_name}
            </button>
          ))}
        </div>
      )}
      {loading && (
        <div className="absolute top-full left-0 right-0 px-4 py-3 bg-background border-b border-border">
          <p className="text-sm text-muted-foreground">Searching…</p>
        </div>
      )}
    </div>
  )
}

export function CityMapPicker({
  center,
  zoom,
  onCenterChange,
  onZoomChange,
  onCitySelect,
  onClear,
  showSearch = true,
  onError,
  className,
  mapKeySuffix,
  cityName,
  cityCountry,
  introMode = false,
  onNext,
  mapOverlay,
}: CityMapPickerProps) {
  const [flyToTarget, setFlyToTarget] = useState<{ lat: number; lng: number } | null>(null)
  const [mapReady, setMapReady] = useState(false)
  const [spinning, setSpinning] = useState(false)
  const mapControlRef = useRef<MapControlHandle | null>(null)
  const spinRef = useRef(false)
  const spinLngRef = useRef(0)
  const mapKey = mapKeySuffix ? `admin-city-picker-${mapKeySuffix}` : "admin-city-picker"

  const safeCenter =
    Number.isFinite(center.lat) && Number.isFinite(center.lng) ? center : DEFAULT_CENTER
  const safeZoom =
    Number.isFinite(zoom) && zoom >= MIN_ZOOM && zoom <= MAX_ZOOM ? Math.round(zoom) : DEFAULT_ZOOM

  const safeZoomRef = useRef(safeZoom)
  useEffect(() => { safeZoomRef.current = safeZoom }, [safeZoom])

  const handleMapReady = useCallback((control: MapControlHandle) => {
    mapControlRef.current = control
    setMapReady(true)
    if (introMode) {
      spinLngRef.current = 0
      spinRef.current = true
      setSpinning(true)
      setTimeout(() => {
        control.flyTo({ center: INTRO_CENTER, zoom: 2, duration: INTRO_FLY_DURATION })
      }, 400)
    }
  }, [introMode])

  useEffect(() => {
    if (!spinning || !mapReady) return
    let frameId: number
    const tick = () => {
      if (!spinRef.current) return
      const ctrl = mapControlRef.current
      if (ctrl?.setCenter) {
        spinLngRef.current = (spinLngRef.current + 0.15) % 360
        ctrl.setCenter({ lat: 20, lng: spinLngRef.current })
      }
      frameId = requestAnimationFrame(tick)
    }
    frameId = requestAnimationFrame(tick)
    return () => cancelAnimationFrame(frameId)
  }, [spinning, mapReady])

  const stopSpinning = useCallback(() => {
    spinRef.current = false
    setSpinning(false)
  }, [])

  /** Restart the spinning intro — called when user clears the search */
  const handleClearCity = useCallback(() => {
    if (introMode && mapReady) {
      spinRef.current = true
      setSpinning(true)
      mapControlRef.current?.flyTo({ center: INTRO_CENTER, zoom: 0, duration: 1500 })
    }
    onClear?.()
  }, [introMode, mapReady, onClear])

  const handleCenterChange = useCallback(
    (pos: { lat: number; lng: number }) => {
      if (spinRef.current) return
      onCenterChange(pos.lat, pos.lng)
      onError?.("")
    },
    [onCenterChange, onError],
  )

  const handleCitySelect = useCallback(
    (lat: number, lng: number, name: string, country: string) => {
      if (spinRef.current) {
        // Globe is spinning — stop it, set zoom state before unblocking CityMapSync
        spinRef.current = false
        onZoomChange(12)
        mapControlRef.current?.flyTo({ center: { lat, lng }, zoom: 12, duration: CITY_FLY_DURATION })
        setTimeout(() => setSpinning(false), CITY_FLY_DURATION)
      } else {
        // Not spinning — fly directly; do NOT call onZoomChange here or CityMapSync will
        // immediately call setZoom(12) and interrupt the flyTo animation
        mapControlRef.current?.flyTo({ center: { lat, lng }, zoom: 12, duration: 1200 })
        // onZoomEnd on the map will call onZoomChange(12) once the animation completes
      }
      onCenterChange(lat, lng)
      onCitySelect?.(lat, lng, name, country)
      onError?.("")
    },
    [onCenterChange, onCitySelect, onError, onZoomChange],
  )

  const mapDefaultCenter = introMode ? INTRO_CENTER : safeCenter
  const mapDefaultZoom = introMode ? 0 : safeZoom

  return (
    <MapProvider libraries={["places"]}>
      <div className={cn("w-full flex flex-col flex-1 min-h-0", className)}>
        {/* Map — search is overlaid at the top */}
        <div
          className="relative flex-1 min-h-[60vh] overflow-hidden"
          onMouseDown={spinning ? stopSpinning : undefined}
          onTouchStart={spinning ? stopSpinning : undefined}
        >
          <MapContainer
            id={CITY_MAP_ID}
            mapKey={mapKey}
            defaultCenter={mapDefaultCenter}
            defaultZoom={mapDefaultZoom}
            minZoom={MIN_ZOOM}
            maxZoom={MAX_ZOOM}
            className="h-full w-full"
            onCenterChange={handleCenterChange}
            onZoomChange={onZoomChange}
            onMapReady={handleMapReady}
            controls={{ zoom: false }}
          >
            <CityMapSync
              zoom={safeZoom}
              flyToTarget={flyToTarget}
              clearFlyToTarget={() => setFlyToTarget(null)}
              mapControlRef={mapControlRef}
              mapReady={mapReady}
              blocked={spinning}
            />
          </MapContainer>

          {/* Search bar overlaid at the top of the map */}
          {showSearch && (
            <div className="absolute top-0 left-0 right-0 z-10">
              <CitySearch
                onSelect={handleCitySelect}
                onError={onError}
                onClear={handleClearCity}
              />
            </div>
          )}

          {mapOverlay}
        </div>
      </div>
    </MapProvider>
  )
}

"use client"

import { useState, useMemo, useRef, useEffect, useCallback } from "react"
