  if (workflowStep === "select-location") {
    const selectedFiction = fictions.find((f) => f.id === formData.fictionId)
    const availableLocations = locations.filter((l) => l.fictionId === formData.fictionId)

    return (
      <WizardShell
        title="Create Scene"
