export interface FictionDetailProps {
  fiction: FictionWithMedia
  initialLocations?: Location[]
  initialCities?: City[]
  /** Server-loaded: other active movies that share a city with this fiction. */
  sameCityRecommendations?: FictionWithMedia[]
  sameCityRecommendationPlaceCounts?: Record<string, number>
  onBack: () => void
  onViewPlace?: (location: Location) => void
}

export function FictionDetail({
  fiction,
  initialLocations,
  initialCities,
  sameCityRecommendations,
  sameCityRecommendationPlaceCounts,
  onBack,
  onViewPlace,
}: FictionDetailProps) {
  const { user } = useAuth()
  const t = useTranslations("Fictions")
  const [allLocations, setAllLocations] = useState<Location[]>(initialLocations ?? [])
  const [fictionCities, setFictionCities] = useState<City[]>(initialCities ?? [])
  const [cityMap, setCityMap] = useState<Map<string, City>>(
    () => new Map((initialCities ?? []).map((c) => [c.id, c]))
  )
  const [sceneCount, setSceneCount] = useState(0)
  const [likeCount, setLikeCount] = useState(0)
  const [liked, setLiked] = useState(false)
  const [likeBusy, setLikeBusy] = useState(false)

  useEffect(() => {
    let cancelled = false
    async function load() {
      if (initialLocations && initialCities) {
        if (cancelled) return
        setAllLocations(initialLocations)
        setFictionCities(initialCities)
        setCityMap(new Map(initialCities.map((c) => [c.id, c])))
        return
      }

      try {
        const [locations, cities] = await Promise.all([
          getFictionLocationsAction(fiction.id),
          getFictionCitiesAction(fiction.id),
        ])
        if (cancelled) return
        setAllLocations(locations)
        setFictionCities(cities)
        setCityMap(new Map(cities.map((c) => [c.id, c])))
      } catch {
        if (cancelled) return
        setAllLocations([])
        setFictionCities([])
        setCityMap(new Map())
      }
    }
    load()
    return () => {
      cancelled = true
    }
  }, [fiction.id, initialLocations, initialCities])

  useEffect(() => {
    let cancelled = false
    listScenesAction({ fictionId: fiction.id, active: "true" })
      .then((scenes) => {
        if (!cancelled) setSceneCount(scenes.length)
      })
      .catch(() => {
        if (!cancelled) setSceneCount(0)
      })
    return () => {
      cancelled = true
    }
  }, [fiction.id])

  useEffect(() => {
    let cancelled = false
    getFictionLikeCountsAction([fiction.id])
      .then((counts) => {
        if (!cancelled) setLikeCount(counts[fiction.id] ?? 0)
      })
      .catch(() => {
        if (!cancelled) setLikeCount(0)
      })
    return () => {
      cancelled = true
    }
  }, [fiction.id])

  useEffect(() => {
    if (!user) {
      setLiked(false)
      return
    }
    let cancelled = false
    getMyLikedFictionIdsAction()
      .then((ids) => {
        if (!cancelled) setLiked(ids.includes(fiction.id))
      })
      .catch(() => {
        if (!cancelled) setLiked(false)
      })
    return () => {
      cancelled = true
    }
  }, [user?.id, fiction.id])

  const [expandedLocation, setExpandedLocation] = useState<string | null>(null)
  const [heroVisible, setHeroVisible] = useState(true)
  const [coverError, setCoverError] = useState(false)
  const heroRef = useRef<HTMLDivElement>(null)
  const scrollRef = useRef<HTMLDivElement>(null)

  const heroSrc =
    !coverError &&
    (fiction.bannerImage?.trim() || fiction.coverImageLarge?.trim() || fiction.coverImage?.trim())
      ? (fiction.bannerImage?.trim() ||
          fiction.coverImageLarge?.trim() ||
          fiction.coverImage?.trim())!
      : DEFAULT_FICTION_COVER
  const coverSrc =
    !coverError && fiction.coverImage?.trim()
      ? fiction.coverImage.trim()
      : DEFAULT_FICTION_COVER

  const locationsByCity = useMemo(() => {
    const map = new Map<string, Location[]>()
    for (const loc of allLocations) {
      const arr = map.get(loc.cityId) || []
      arr.push(loc)
      map.set(loc.cityId, arr)
    }
    return map
  }, [allLocations])

  // Detect when hero goes out of view for sticky header (within scroll container)
  useEffect(() => {
    const root = scrollRef.current
    const hero = heroRef.current
    if (!root || !hero) return
    const observer = new IntersectionObserver(
      ([entry]) => {
        setHeroVisible(entry.isIntersecting)
      },
      { threshold: 0.1, root },
    )

    observer.observe(hero)
    return () => observer.disconnect()
  }, [])

  const firstCityId = fictionCities[0]?.id ?? allLocations[0]?.cityId
  const exploreMapHref = firstCityId
    ? `/map?fiction=${encodeURIComponent(fiction.id)}&city=${encodeURIComponent(firstCityId)}`
    : `/map?fiction=${encodeURIComponent(fiction.id)}`
  const isBook = fiction.type === "book"
  const locationLabel = isBook ? t("locationLabelBook") : t("locationLabelFilming")

  async function handleToggleLike() {
    if (!user || likeBusy) return
    const wasLiked = liked
    const prevCount = likeCount
    setLikeBusy(true)
    setLiked(!wasLiked)
    setLikeCount(wasLiked ? Math.max(0, prevCount - 1) : prevCount + 1)
    try {
      const result = await toggleFictionLikeAction(fiction.id)
      if (!result.success) {
        setLiked(wasLiked)
        setLikeCount(prevCount)
        return
      }
      setLiked(result.liked)
      setLikeCount(result.likeCount)
    } catch {
      setLiked(wasLiked)
      setLikeCount(prevCount)
    } finally {
      setLikeBusy(false)
    }
  }

  return (
    <div ref={scrollRef} className="relative h-full overflow-y-auto bg-background">
      {/* Sticky header (appears when hero is out of view) */}
      {!heroVisible && (
        <PageStickyBar
          className="px-6"
          leading={
            <>
              <button
                onClick={onBack}
                className="flex h-9 w-9 shrink-0 items-center justify-center rounded-full text-foreground transition-colors hover:bg-secondary"
                aria-label="Back"
              >
                <ArrowLeft className="h-4 w-4" />
              </button>
              <div className="relative h-10 w-7 shrink-0 overflow-hidden rounded-md border border-border/60 bg-muted/40">
                <Image
                  src={coverSrc}
                  alt={fiction.title}
                  fill
                  className="object-cover"
                  sizes="28px"
                  onError={() => setCoverError(true)}
                />
              </div>
            </>
          }
          title={
            <div className="min-w-0">
              <h2 className="truncate text-sm font-semibold text-foreground">{fiction.title}</h2>
              <p className="line-clamp-1 text-xs text-muted-foreground">{fiction.description}</p>
            </div>
          }
          trailing={
            <div className="flex items-center gap-2">
              {user && (
                <Button
                  variant="secondary"
                  size="sm"
                  onClick={handleToggleLike}
                  disabled={likeBusy}
                  aria-label={liked ? "Unlike" : "Like"}
                  className="gap-1.5"
                >
                  <Heart
                    className={`h-4 w-4 ${liked ? "text-rose-500" : ""}`}
                    fill={liked ? "currentColor" : "transparent"}
                  />
                  {likeCount > 0 && <span className="text-xs tabular-nums">{likeCount}</span>}
                </Button>
              )}
              <Button asChild size="sm" variant="cta">
                <Link href={exploreMapHref}>
                  <Compass className="h-4 w-4" />
                  <span>Explore Map</span>
                </Link>
              </Button>
            </div>
          }
        />
      )}

      {/* Hero: banner when set, else cover */}
      <div ref={heroRef} className="relative h-[320px] md:h-[380px] flex-shrink-0 overflow-hidden">
        <Image
          src={heroSrc}
          alt={fiction.title}
          fill
          className="object-cover"
          sizes="100vw"
          priority
          onError={() => setCoverError(true)}
        />
        <div className="absolute inset-0 bg-gradient-to-t from-background via-background/35 to-transparent" />
        <div className="absolute inset-0 bg-gradient-to-r from-background/30 to-transparent" />

        {/* Back button */}
        <button
          onClick={onBack}
          className="absolute left-6 top-6 z-10 flex h-9 w-9 items-center justify-center rounded-full bg-background/60 text-foreground backdrop-blur-sm transition-colors hover:bg-background/80"
        >
          <ArrowLeft className="h-4 w-4" />
        </button>

        {/* Info overlay: cover poster + title, meta */}
        <div className="absolute bottom-0 left-0 right-0 z-10 px-8 pb-8">
          <div className="flex flex-row items-end justify-between gap-4">
            <div className="flex min-w-0 flex-1 flex-row items-end gap-4">
              {/* Cover poster */}
              <div className="relative h-[112px] w-[75px] flex-shrink-0 overflow-hidden rounded-lg border border-border/60 shadow-xl sm:h-[186px] sm:w-[124px] md:h-[222px] md:w-[148px]">
                <Image
                  src={coverSrc}
                  alt={fiction.title}
                  fill
                  className="object-cover"
                  sizes="148px"
                  onError={() => setCoverError(true)}
                />
              </div>
              <div className="min-w-0 flex-1">
                <div className="flex flex-wrap items-center gap-2">
                  <Badge variant="secondary" className="text-xs">
                    {fiction.type === "tv-series" ? "TV Series" : fiction.type === "book" ? "Book" : "Movie"}
                  </Badge>
                  <Badge variant="outline" className="text-xs">
                    {fiction.genre}
                  </Badge>
                </div>
                <h1 className="mt-2 font-sans text-4xl font-bold tracking-tight text-foreground md:text-5xl">
                  {fiction.title}
                </h1>
                <div className="mt-2 flex flex-wrap items-center gap-4 text-sm text-muted-foreground">
                  <span className="flex items-center gap-1">
                    <Clock className="h-3.5 w-3.5" />
                    {fiction.year}
                  </span>
                  {fiction.author && (
                    <span>
                      {fiction.type === "movie"
                        ? "Directed by "
                        : fiction.type === "tv-series"
                          ? "Created by "
                          : "By "}
                      <span className="text-foreground">{fiction.author}</span>
                    </span>
                  )}
                  <span className="flex items-center gap-1">
                    <MapPin className="h-3.5 w-3.5" />
                    {allLocations.length} location{allLocations.length > 1 ? "s" : ""} in{" "}
                    {fictionCities.length} cit{fictionCities.length > 1 ? "ies" : "y"}
                    {(fiction.type === "movie" || fiction.type === "tv-series") && sceneCount > 0 && (
                      <>
                        {" "}
                        &middot; {sceneCount} scene{sceneCount > 1 ? "s" : ""}
                      </>
                    )}
                  </span>
                </div>
              </div>
            </div>
            <div className="flex shrink-0 items-center gap-2">
              {user && (
                <Button
                  variant="secondary"
                  size="sm"
                  onClick={handleToggleLike}
                  disabled={likeBusy}
                  aria-label={liked ? "Unlike" : "Like"}
                  className="gap-1.5"
                >
                  <Heart
                    className={`h-4 w-4 ${liked ? "text-rose-500" : ""}`}
                    fill={liked ? "currentColor" : "transparent"}
                  />
                  {likeCount > 0 && <span className="text-xs tabular-nums">{likeCount}</span>}
                </Button>
              )}
              <Button asChild size="sm" variant="cta">
                <Link href={exploreMapHref}>
                  <Compass className="h-4 w-4" />
                  <span>Explore Map</span>
                </Link>
              </Button>
            </div>
          </div>
        </div>
      </div>

      {/* Description */}
      {fiction.description && (
        <div className="px-8 pb-2 pt-6">
          <p className="max-w-2xl text-sm leading-relaxed text-muted-foreground">
            {fiction.description}
          </p>
        </div>
      )}

      {/* Locations - full page scroll */}
      <div className="px-8 py-6">
        <div className="mb-6 max-w-3xl">
          <h2 className="text-xl font-semibold text-foreground">
            {t("howToVisitTitle", { title: fiction.title, locationLabel })}
          </h2>
          <p className="mt-2 text-sm text-muted-foreground">
            {t("howToVisitDescription")}
          </p>
        </div>
        {Array.from(locationsByCity.entries()).map(([cityId, locs]) => {
          const city = cityMap.get(cityId)
          const activeLocation = locs.find((loc) => loc.id === expandedLocation)
          return (
            <div key={cityId} className="mb-8">
              <div className="mb-4 flex items-center gap-2">
                <MapPin className="h-4 w-4 text-primary" />
                <h3 className="text-lg font-semibold text-foreground">
                  {city?.name}, {city?.country}
                </h3>
                <span className="text-sm text-muted-foreground">
                  &middot; {t("placeCount", { count: locs.length })}
                </span>
              </div>

              <div className="grid grid-cols-2 gap-4 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-6">
                {locs.map((loc) => {
                  const isExpanded = expandedLocation === loc.id
                  const handleClick = () => {
                    if (onViewPlace) {
                      onViewPlace(loc)
                      return
                    }
                    setExpandedLocation(isExpanded ? null : loc.id)
                  }
                  const hoverLabel = onViewPlace
                    ? "Explore this place"
                    : isExpanded
                      ? "Hide details"
                      : "View details"
                  return (
                    <LocationCard
                      key={loc.id}
                      location={loc}
                      compact
                      onClick={handleClick}
                      hoverLabel={hoverLabel}
                    />
                  )
                })}
              </div>

              {activeLocation && !onViewPlace && (
                <LocationDetailPanel location={activeLocation} />
              )}
            </div>
          )
        })}
      </div>

      {sameCityRecommendations && sameCityRecommendations.length > 0 && (
        <div className="border-t border-border/60 px-8 py-5 pb-8">
          <div className="mb-1.5 flex items-center gap-1.5">
            <Sparkles className="h-3.5 w-3.5 shrink-0 text-primary" aria-hidden />
            <h2 className="text-sm font-semibold text-foreground">
              {t("sameCityRecommendationsTitle")}
            </h2>
          </div>
          <p className="mb-3 max-w-xl text-xs leading-snug text-muted-foreground">
            {t("sameCityRecommendationsDescription")}
          </p>
          <div className="grid grid-cols-3 gap-2.5 sm:grid-cols-4 md:grid-cols-5 lg:grid-cols-6 xl:grid-cols-7">
            {sameCityRecommendations.map((rec) => (
              <FictionCard
                key={rec.id}
                fiction={rec}
                locationCount={sameCityRecommendationPlaceCounts?.[rec.id] ?? 0}
                href={`/fictions/${rec.slug ?? rec.id}`}
              />
            ))}
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import { useState, useMemo, useEffect, useRef, useCallback, useTransition, startTransition } from "react"
import type { FictionWithMedia } from "@/src/fictions/domain/fiction.entity"
import type { Location } from "@/src/locations/domain/location.entity"
import { FictionCard } from "@/components/fictions/fiction-card"
import { FictionDetail } from "@/components/fictions/fiction-detail"
import { PageHero } from "@/components/layout/page-hero"
import { PageStickyBar } from "@/components/layout/page-sticky-bar"
import { SearchInput } from "@/components/ui/search-input"
import { Film } from "lucide-react"
import { useAuth } from "@/context/auth-context"
import { getFictionLikeCountsAction } from "@/src/fictions/infrastructure/next/fiction.actions"
import { getMyLikedFictionIdsAction, toggleFictionLikeAction } from "@/src/users/infrastructure/next/user.actions"

type FictionLandingView = "browse" | "detail"

const ITEMS_PER_PAGE = 20

const emptyState = (
  <div className="flex flex-col items-center justify-center py-20 text-center">
    <Film className="mb-3 h-10 w-10 text-muted-foreground/40" />
    <p className="text-sm text-muted-foreground">No fictions found</p>
  </div>
)

interface FictionLandingProps {
  /** Fictions from DB (server). When provided, no client fetch for list. */
  initialFictions?: FictionWithMedia[]
  /** Scene counts per fiction id pre-fetched server-side. */
  initialSceneCounts?: Record<string, number>
  /** Like counts per fiction id pre-fetched server-side. */
  initialLikeCounts?: Record<string, number>
  /** Place counts per fiction id pre-fetched server-side. */
  initialPlaceCounts?: Record<string, number>
  onViewPlace?: (location: Location) => void
  focusFictionId?: string | null
  onFocusHandled?: () => void
}

export function FictionLanding({
  initialFictions,
  initialSceneCounts,
  initialLikeCounts,
  initialPlaceCounts,
  onViewPlace,
  focusFictionId,
  onFocusHandled,
}: FictionLandingProps) {
  const { user } = useAuth()
  const [allFictions, setAllFictions] = useState<FictionWithMedia[]>(initialFictions ?? [])
  const [locationCountMap, setLocationCountMap] = useState<Map<string, number>>(
    () => new Map(Object.entries(initialPlaceCounts ?? {}).map(([id, count]) => [id, Number(count)]))
  )
  const [sceneCountMap] = useState<Map<string, number>>(
    () => new Map(Object.entries(initialSceneCounts ?? {}))
  )
  const [likeCountByFictionId, setLikeCountByFictionId] = useState<Record<string, number>>(
    initialLikeCounts ?? {}
  )
  const [likedFictionIds, setLikedFictionIds] = useState<string[]>([])

  const likedFictionIdSet = useMemo(() => new Set(likedFictionIds), [likedFictionIds])

  useEffect(() => {
    if (initialFictions !== undefined) {
      setAllFictions(initialFictions)
    }
  }, [initialFictions])

  useEffect(() => {
    if (initialPlaceCounts === undefined) return
    setLocationCountMap(
      new Map(Object.entries(initialPlaceCounts).map(([id, count]) => [id, Number(count)]))
    )
  }, [initialPlaceCounts])

  const [view, setView] = useState<FictionLandingView>("browse")
  const [selectedFiction, setSelectedFiction] = useState<FictionWithMedia | null>(null)
  const [search, setSearch] = useState("")
  const [page, setPage] = useState(0)
  const [stickyHeader, setStickyHeader] = useState(false)
  const [isPending, startLoadTransition] = useTransition()
  const observerTarget = useRef<HTMLDivElement>(null)
  const heroSectionRef = useRef<HTMLDivElement>(null)
  const scrollContainerRef = useRef<HTMLDivElement>(null)

  const handleSearchChange = useCallback((value: string) => {
    setSearch(value)
    setPage(0)
  }, [])

  useEffect(() => {
    const container = scrollContainerRef.current
    if (!container) return
    const handleScroll = () => {
      const hero = heroSectionRef.current
      if (!hero) return
      const heroBottom = hero.getBoundingClientRect().bottom
      startTransition(() => setStickyHeader(heroBottom <= 0))
    }
    container.addEventListener("scroll", handleScroll, { passive: true })
    return () => container.removeEventListener("scroll", handleScroll)
  }, [])

  const filtered = useMemo(() => {
    if (!search.trim()) return allFictions
    const q = search.toLowerCase()
    return allFictions.filter(
      (f) =>
        f.title.toLowerCase().includes(q) ||
        f.genre.toLowerCase().includes(q) ||
        (f.author?.toLowerCase().includes(q) ?? false),
    )
  }, [search, allFictions])

  const displayedItems = filtered.slice(0, (page + 1) * ITEMS_PER_PAGE)
  const hasMore = displayedItems.length < filtered.length

  useEffect(() => {
    const container = scrollContainerRef.current
    if (!container) return
    const observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting && hasMore && !isPending) {
          startLoadTransition(() => {
            setPage((p) => p + 1)
          })
        }
      },
      { threshold: 0.1, root: container },
    )
    if (observerTarget.current) {
      observer.observe(observerTarget.current)
    }
    return () => observer.disconnect()
  }, [hasMore, isPending])

  useEffect(() => {
    if (!focusFictionId) return
    const target = allFictions.find((f) => f.id === focusFictionId) || null
    if (target) {
      setSelectedFiction(target)
      setView("detail")
    }
    onFocusHandled?.()
  }, [focusFictionId, onFocusHandled, allFictions])

  // User-specific likes: which fictions are liked by the logged-in user.
  useEffect(() => {
    if (!user) {
      setLikedFictionIds([])
      return
    }

    let cancelled = false
    ;(async () => {
      try {
        const data = await getMyLikedFictionIdsAction()
        if (!cancelled) setLikedFictionIds(data)
      } catch {
        if (!cancelled) setLikedFictionIds([])
      }
    })()

    return () => {
      cancelled = true
    }
  }, [user?.id])

  // Track which fiction ids already have their like count loaded.
  // Initialised with the server-provided ids to avoid redundant fetches on scroll.
  const fetchedLikeIdsRef = useRef<Set<string>>(new Set(Object.keys(initialLikeCounts ?? {})))

  const displayedFictionIdsKey = useMemo(
    () => displayedItems.map((f) => f.id).join(","),
    [displayedItems],
  )

  // Public like counts — only fetch ids that haven't been loaded yet.
  useEffect(() => {
    const ids = displayedFictionIdsKey ? displayedFictionIdsKey.split(",").filter(Boolean) : []
    const newIds = ids.filter((id) => !fetchedLikeIdsRef.current.has(id))
    if (newIds.length === 0) return

    let cancelled = false
    ;(async () => {
      try {
        const newCounts = await getFictionLikeCountsAction(newIds)
        if (!cancelled) {
          for (const id of newIds) fetchedLikeIdsRef.current.add(id)
          setLikeCountByFictionId((prev) => ({ ...prev, ...newCounts }))
        }
      } catch {
        // noop — stale counts remain visible
      }
    })()

    return () => {
      cancelled = true
    }
  }, [displayedFictionIdsKey])

  const toggleLike = useCallback(
    async (fictionId: string) => {
      if (!user) return

      const wasLiked = likedFictionIdSet.has(fictionId)
      const prevCount = likeCountByFictionId[fictionId] ?? 0

      // Optimistic update — instant feedback
      setLikedFictionIds((prev) => {
        const set = new Set(prev)
        if (wasLiked) set.delete(fictionId)
        else set.add(fictionId)
        return Array.from(set)
      })
      setLikeCountByFictionId((prev) => ({
        ...prev,
        [fictionId]: wasLiked ? Math.max(0, prevCount - 1) : prevCount + 1,
      }))

      const result = await toggleFictionLikeAction(fictionId)

      if (!result.success) {
        // Revert on error
        setLikedFictionIds((prev) => {
          const set = new Set(prev)
          if (wasLiked) set.add(fictionId)
          else set.delete(fictionId)
          return Array.from(set)
        })
        setLikeCountByFictionId((prev) => ({ ...prev, [fictionId]: prevCount }))
        return
      }

      // Reconcile with authoritative server values
      setLikeCountByFictionId((prev) => ({ ...prev, [fictionId]: result.likeCount }))
      setLikedFictionIds((prev) => {
        const set = new Set(prev)
        if (result.liked) set.add(fictionId)
        else set.delete(fictionId)
        return Array.from(set)
      })
    },
    [user?.id, likedFictionIdSet, likeCountByFictionId],
  )

  if (view === "detail" && selectedFiction) {
    return (
      <FictionDetail
        fiction={selectedFiction}
        onBack={() => {
          setView("browse")
          setSelectedFiction(null)
        }}
        onViewPlace={onViewPlace}
      />
    )
  }

  return (
    <div
      ref={scrollContainerRef}
      className="relative h-full overflow-y-auto bg-background"
    >
      <div ref={heroSectionRef}>
        <PageHero
          title="Fictions"
          subtitle="Explore filming locations from your favorite movies and series"
        >
          <SearchInput
            value={search}
            onChange={handleSearchChange}
            placeholder="Search by title, genre, or director…"
            size="default"
          />
        </PageHero>
      </div>

      {stickyHeader && (
        <PageStickyBar title={<h2 className="text-base font-bold text-foreground">Fictions</h2>}>
          <SearchInput
            value={search}
            onChange={handleSearchChange}
            placeholder="Search…"
            size="compact"
          />
        </PageStickyBar>
      )}

      <div className="px-8 pb-16 pt-2">
        {displayedItems.length === 0 ? (
          emptyState
        ) : (
          <>
            <div className="grid grid-cols-2 gap-2.5 pb-8 md:grid-cols-5 lg:grid-cols-7 xl:grid-cols-8">
              {displayedItems.map((fiction) => (
                <FictionCard
                  key={fiction.id}
                  fiction={fiction}
                  locationCount={locationCountMap.get(fiction.id) ?? 0}
                  sceneCount={sceneCountMap.get(fiction.id) ?? 0}
                  href={`/fictions/${fiction.slug ?? fiction.id}`}
                  likeCount={likeCountByFictionId[fiction.id] ?? 0}
                  liked={likedFictionIdSet.has(fiction.id)}
                  onToggleLike={user ? toggleLike : undefined}
                />
              ))}
            </div>

            {hasMore && (
              <div ref={observerTarget} className="flex items-center justify-center py-8">
                <div className="flex items-center gap-2 text-sm text-muted-foreground">
                  <div className="h-2 w-2 animate-pulse rounded-full bg-muted-foreground/40" />
                  <span>Loading more…</span>
                </div>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  )
}

"use client"

import { X, MapPin, Quote, Lightbulb, Film, ArrowRight, Box } from "lucide-react"
import { useState, useEffect } from "react"
import { useTranslations } from "next-intl"
import type { Location } from "@/src/locations/domain/location.entity"
import type { FictionWithMedia } from "@/src/fictions/domain/fiction.entity"
import type { Scene } from "@/src/scenes/domain/scene.entity"
import { Badge } from "@/components/ui/badge"
import { ScrollArea } from "@/components/ui/scroll-area"
import { DEFAULT_FICTION_ACCENT } from "@/lib/constants/placeholders"
import Image from "next/image"
import { SceneClipPanelCard } from "./scene-clip-panel-card"
import { getActiveFictionsAction } from "@/src/fictions/infrastructure/next/fiction.actions"
import { listScenesAction } from "@/src/scenes/infrastructure/next/scene.actions"

interface LocationDetailProps {
  location: Location
  /** When provided (e.g. from map page), used instead of fetching. */
  fiction?: FictionWithMedia | null
  onClose: () => void
  onViewPlace?: (location: Location) => void
  onView3D?: () => void
}

export function LocationDetail({
  location,
  fiction: fictionProp,
  onClose,
  onViewPlace,
  onView3D,
}: LocationDetailProps) {
  const t = useTranslations("Map")
  const [fiction, setFiction] = useState<FictionWithMedia | undefined>(
    fictionProp ?? undefined
  )
  const [placeScenes, setPlaceScenes] = useState<Scene[]>([])

  useEffect(() => {
    let cancelled = false
    if (fictionProp !== undefined) {
      setFiction(fictionProp ?? undefined)
    } else {
      getActiveFictionsAction()
        .then((rows) => {
          if (cancelled) return
          const hit = rows.find((f) => f.id === location.fictionId)
          setFiction(hit ?? undefined)
        })
        .catch(() => {
          if (!cancelled) setFiction(undefined)
        })
    }
    return () => {
      cancelled = true
    }
  }, [location.fictionId, fictionProp])

  useEffect(() => {
    let cancelled = false
    listScenesAction({ placeId: location.id, active: "true" })
      .then((s) => {
        if (!cancelled) setPlaceScenes(s)
      })
      .catch(() => {
        if (!cancelled) setPlaceScenes([])
      })
    return () => {
      cancelled = true
    }
  }, [location.id])

  const sceneCount = placeScenes.length

  return (
    <>
      <div
        className="absolute inset-0 z-[1990] bg-black/40"
        onClick={onClose}
        aria-hidden="true"
      />
      <div className="absolute inset-y-0 right-0 z-[2000] flex w-full flex-col border-l border-border bg-background sm:w-[420px]">
        {/* Header image */}
        <div className="relative h-56 shrink-0">
          <Image
            src={location.image || "/placeholder.svg"}
            alt={location.name}
            fill
            className="object-cover"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-background via-background/30 to-transparent" />
          <button
            onClick={onClose}
            className="absolute right-3 top-3 flex h-8 w-8 items-center justify-center rounded-full bg-background/80 backdrop-blur-sm transition-colors hover:bg-background"
            aria-label="Close location detail"
          >
            <X className="h-4 w-4 text-foreground" />
          </button>
          {fiction && (
            <div className="absolute bottom-3 left-4">
              <Badge
                className="text-xs border-0"
                style={{ backgroundColor: DEFAULT_FICTION_ACCENT, color: "#fff" }}
              >
                <Film className="mr-1 h-3 w-3" />
                {fiction.title}
              </Badge>
            </div>
          )}
        </div>

        {/* Content */}
        <ScrollArea className="min-h-0 flex-1">
          <div className="flex flex-col gap-5 p-5">
            {/* Title and address */}
            <div className="flex flex-col gap-1.5">
              <h2 className="text-xl font-bold text-foreground leading-tight text-balance">
                {location.name}
              </h2>
              <div className="flex items-center gap-1.5 text-muted-foreground">
                <MapPin className="h-3.5 w-3.5 shrink-0" />
                <span className="text-xs">{location.address}</span>
              </div>
            </div>

            {/* Description */}
            <div className="flex flex-col gap-2">
              <h3 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">
                About this Location
              </h3>
              <p className="text-sm leading-relaxed text-secondary-foreground">
                {location.description}
              </p>
            </div>

            {/* Scene (text) */}
            <div className="flex flex-col gap-2 rounded-lg border border-border bg-card p-4">
              <h3 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">
                The Scene
              </h3>
              <p className="text-sm leading-relaxed text-secondary-foreground">
                {location.sceneDescription}
              </p>
              {location.sceneQuote && (
                <div className="mt-2 flex gap-2 rounded-md bg-secondary/60 p-3">
                  <Quote className="mt-0.5 h-4 w-4 shrink-0 text-primary" />
                  <p className="text-sm italic text-foreground">
                    {location.sceneQuote}
                  </p>
                </div>
              )}
            </div>

            {placeScenes.length > 0 && (
              <>
                <h3 className="text-[11px] font-semibold uppercase tracking-wider text-muted-foreground">
                  {t("sceneClips")} · {t("sceneClipCount", { count: placeScenes.length })}
                </h3>
                {placeScenes.slice(0, 5).map((sc) => (
                  <SceneClipPanelCard
                    key={sc.id}
                    scene={sc}
                    fiction={fiction ?? null}
                    noVideoLabel={t("noSceneVideo")}
                    playVideoLabel={t("playSceneVideo")}
                    filmTimelineCaption={t("filmTimelineCaption")}
                  />
                ))}
                {placeScenes.length > 5 && (
                  <p className="text-center text-xs text-muted-foreground">
                    +{placeScenes.length - 5} more on the place page
                  </p>
                )}
              </>
            )}

            {/* Visit Tip */}
            {location.visitTip && (
              <div className="flex gap-2.5 rounded-lg border border-primary/20 bg-primary/5 p-4">
                <Lightbulb className="mt-0.5 h-4 w-4 shrink-0 text-primary" />
                <div className="flex flex-col gap-1">
                  <h3 className="text-xs font-semibold uppercase tracking-wider text-primary">
                    Visitor Tip
                  </h3>
                  <p className="text-sm leading-relaxed text-secondary-foreground">
                    {location.visitTip}
                  </p>
                </div>
              </div>
            )}

            {/* View Place Page CTA */}
            {onViewPlace && (
              <button
                onClick={() => onViewPlace(location)}
                className="flex w-full items-center justify-between rounded-xl border border-primary/30 bg-primary/5 px-4 py-3 text-left transition-colors hover:bg-primary/10"
              >
                <div className="flex flex-col gap-0.5">
                  <span className="text-sm font-semibold text-foreground">
                    Explore this place
                  </span>
                  <span className="text-xs text-muted-foreground">
                    {sceneCount} scene{sceneCount !== 1 ? "s" : ""} filmed here
                  </span>
                </div>
                <ArrowRight className="h-4 w-4 text-primary" />
              </button>
            )}

            {/* 3D View CTA — temporarily disabled */}
            {/* {onView3D && (
              <button
                onClick={onView3D}
                className="flex w-full items-center justify-between rounded-xl border border-cyan-500/30 bg-cyan-500/5 px-4 py-3 text-left transition-colors hover:bg-cyan-500/10"
              >
                <div className="flex flex-col gap-0.5">
                  <span className="text-sm font-semibold text-foreground">
                    View in 3D
                  </span>
                  <span className="text-xs text-muted-foreground">
                    Photorealistic city model
                  </span>
                </div>
                <Box className="h-4 w-4 text-cyan-500" />
              </button>
            )} */}

            {/* Fiction info */}
            {fiction && (
              <div className="flex flex-col gap-2 rounded-lg border border-border bg-card p-4">
                <h3 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">
                  Featured In
                </h3>
                <div className="flex items-center gap-3">
                  <div
                    className="flex h-12 w-12 shrink-0 items-center justify-center rounded-lg"
                    style={{ backgroundColor: DEFAULT_FICTION_ACCENT }}
                  >
                    <Film className="h-6 w-6 text-foreground" />
                  </div>
                  <div className="flex flex-col">
                    <span className="text-sm font-semibold text-foreground">{fiction.title}</span>
                    <span className="text-xs text-muted-foreground">
                      {fiction.year} &middot; {fiction.genre}
                      {fiction.author ? ` \u00B7 ${fiction.author}` : ""}
                    </span>
                  </div>
                </div>
              </div>
            )}
          </div>
        </ScrollArea>
      </div>
    </>
  )
}

"use client"

import { useEffect } from "react"
import { useMapControl } from "@/lib/map"

const TILT_3D = 60
const HEADING_3D = 320
const ZOOM_3D_MIN = 16

interface Map3DToggleProps {
  is3D: boolean
  onToggle: (is3D: boolean) => void
  cityId?: string
}

export function Map3DToggle({ is3D, onToggle, cityId }: Map3DToggleProps) {
  const mapControl = useMapControl()

  // When city changes while in 3D, restore 3D view (tilt, heading, zoom 18)
  useEffect(() => {
    if (!is3D || !mapControl?.easeTo || cityId == null) return
    mapControl.easeTo({
      tilt: TILT_3D,
      heading: HEADING_3D,
      zoom: ZOOM_3D_MIN,
      duration: 800,
    })
  }, [cityId, mapControl])

  const handleToggle = () => {
    if (!mapControl) return

    if (!is3D) {
      const currentZoom = mapControl.getZoom() ?? ZOOM_3D_MIN
      const targetZoom = Math.max(currentZoom, ZOOM_3D_MIN)
      if (mapControl.easeTo) {
        mapControl.easeTo({ tilt: TILT_3D, heading: HEADING_3D, zoom: targetZoom, duration: 1200 })
      } else {
        mapControl.setZoom(targetZoom)
        mapControl.setTilt?.(TILT_3D)
        mapControl.setHeading?.(HEADING_3D)
      }
      onToggle(true)
    } else {
      if (mapControl.easeTo) {
        mapControl.easeTo({ tilt: 0, heading: 0, duration: 1200 })
      } else {
        mapControl.setTilt?.(0)
        mapControl.setHeading?.(0)
      }
      onToggle(false)
    }
  }

  return (
    <button
      onClick={handleToggle}
      className={`flex h-9 w-9 items-center justify-center rounded-lg border backdrop-blur-md transition-all ${
        is3D
          ? "border-primary/50 bg-primary/20 text-primary shadow-[0_0_0_2px_hsl(36_90%_55%/0.15)]"
          : "border-chrome-border bg-chrome/90 text-foreground hover:bg-chrome-hover"
      }`}
      title={is3D ? "Switch to 2D view" : "Switch to 3D view"}
      aria-label={is3D ? "Switch to 2D view" : "Switch to 3D view"}
    >
      {is3D ? (
        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="shrink-0" aria-hidden>
          <rect x="3" y="3" width="18" height="18" rx="1" />
        </svg>
      ) : (
        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="shrink-0" aria-hidden>
          <path d="M12 2L22 8v8l-10 6-10-6V8L12 2z" />
          <path d="M12 2v12M22 8l-10 6M2 8l10 6" />
        </svg>
      )}
    </button>
  )
}

"use client"

import { useState, useMemo, useRef, useEffect } from "react"
import Image from "next/image"
import { ArrowLeft, MapPin, Play, Lightbulb, Quote, Film, Tv, Clock } from "lucide-react"
import { Badge } from "@/components/ui/badge"
import { PageStickyBar } from "@/components/layout/page-sticky-bar"
import type { Location } from "@/src/locations/domain/location.entity"
import type { Scene } from "@/src/scenes/domain/scene.entity"
import type { Fiction, FictionWithMedia } from "@/src/fictions/domain/fiction.entity"
import type { City } from "@/src/cities/domain/city.entity"
import { DEFAULT_FICTION_ACCENT } from "@/lib/constants/placeholders"
import { SceneWatchView } from "@/components/scenes/scene-watch-view"
import { getAllCitiesAction } from "@/src/cities/infrastructure/next/city.actions"
import { getActiveFictionsAction } from "@/src/fictions/infrastructure/next/fiction.actions"
import { getPlaceLocationAction } from "@/src/places/infrastructure/next/place.actions"
import { listScenesAction } from "@/src/scenes/infrastructure/next/scene.actions"

export interface PlacePageProps {
  location: Location
  /** When provided (e.g. from map), used instead of fetching. */
  fiction?: Fiction | FictionWithMedia | null
  /** When provided (e.g. from map), used instead of fetching. */
  city?: City | null
  onBack: () => void
}

export function PlacePage({
  location,
  fiction: fictionProp,
  city: cityProp,
  onBack,
}: PlacePageProps) {
  const [fiction, setFiction] = useState<Fiction | undefined>(fictionProp ?? undefined)
  const [city, setCity] = useState<City | undefined>(cityProp ?? undefined)
  const [scenes, setScenes] = useState<Scene[]>([])
  const [fictionScenes, setFictionScenes] = useState<Scene[]>([])
  const [sceneLocations, setSceneLocations] = useState<Map<string, Location>>(new Map())

  useEffect(() => {
    if (fictionProp !== undefined) setFiction(fictionProp ?? undefined)
    if (cityProp !== undefined) setCity(cityProp ?? undefined)
  }, [fictionProp, cityProp])

  useEffect(() => {
    let cancelled = false
    async function loadData() {
      const [f, c] = await Promise.all([
        fictionProp !== undefined
          ? Promise.resolve(fictionProp ?? null)
          : getActiveFictionsAction().then((rows) => rows.find((item) => item.id === location.fictionId) ?? null),
        cityProp !== undefined
          ? Promise.resolve(cityProp ?? null)
          : getAllCitiesAction()
              .then((rows) => rows.find((item) => item.id === location.cityId) ?? null),
      ])
      if (cancelled) return
      setFiction(f ?? undefined)
      setCity(c ?? undefined)

      const s = await listScenesAction({ placeId: location.id, active: "true" })
      if (cancelled) return
      setScenes(s)

      let fs = s
      if (f) {
        fs = await listScenesAction({ fictionId: f.id, active: "true" })
      }
      if (cancelled) return
      setFictionScenes(fs)
      const placeIds = [...new Set(fs.map((scene) => scene.placeId))]
      const placeEntries = await Promise.all(
        placeIds.map(async (id) => {
          const place = await getPlaceLocationAction(id)
          if (!place) return null
          return { placeId: id, place }
        }),
      )
      if (cancelled) return
      const locMap = new Map<string, Location>()
      for (const entry of placeEntries) {
        if (!entry) continue
        const matchingScene = fs.find((scene) => scene.placeId === entry.placeId)
        if (matchingScene) locMap.set(matchingScene.locationId, entry.place)
        locMap.set(entry.placeId, entry.place)
      }
      setSceneLocations(locMap)
    }
    loadData()
    return () => {
      cancelled = true
    }
  }, [location.id, location.fictionId, location.cityId, fictionProp, cityProp])

  // For TV series group by season; for movies/books keep flat
  const isTvSeries = fiction?.type === "tv-series"
  const seasons = useMemo(() => {
    if (!isTvSeries) return []
    const map = new Map<number, Scene[]>()
    for (const s of scenes) {
      const seasonNum = s.season ?? 1
      const arr = map.get(seasonNum) ?? []
      arr.push(s)
      map.set(seasonNum, arr)
    }
    return Array.from(map.entries()).sort((a, b) => a[0] - b[0])
  }, [scenes, isTvSeries])

  const [selectedSeason, setSelectedSeason] = useState<number>(seasons[0]?.[0] ?? 1)
  const [sceneView, setSceneView] = useState<"detail" | "video">("detail")
  const [watchSceneId, setWatchSceneId] = useState<string | null>(null)
  const [heroVisible, setHeroVisible] = useState(true)
  const heroRef = useRef<HTMLDivElement>(null)
  const scrollRef = useRef<HTMLDivElement>(null)

  // Detect when hero leaves viewport for sticky header
  useEffect(() => {
    const container = scrollRef.current
    if (!container) return
    const handleScroll = () => {
      const hero = heroRef.current
      if (!hero) return
      setStickyHeader(hero.getBoundingClientRect().bottom <= 0)
    }
    container.addEventListener("scroll", handleScroll, { passive: true })
    return () => container.removeEventListener("scroll", handleScroll)
  }, [])
  const [stickyHeader, setStickyHeader] = useState(false)

  const displayedScenes = isTvSeries
    ? seasons.find(([s]) => s === selectedSeason)?.[1] ?? []
    : scenes
  const currentWatchScene = useMemo(
    () => fictionScenes.find((scene) => scene.id === watchSceneId) ?? null,
    [fictionScenes, watchSceneId],
  )

  useEffect(() => {
    setWatchSceneId(null)
  }, [location.id])

  if (currentWatchScene) {
    const upNextScenes = fictionScenes.filter((scene) => scene.id !== currentWatchScene.id)

    return (
      <SceneWatchView
        currentWatchScene={currentWatchScene}
        fiction={fiction}
        isTvSeries={isTvSeries}
        upNextScenes={upNextScenes}
        sceneLocations={sceneLocations}
        onBack={() => setWatchSceneId(null)}
        onSelectScene={(scene) => setWatchSceneId(scene.id)}
      />
    )
  }

  return (
    <div ref={scrollRef} className="relative h-full overflow-y-auto bg-background">
      {/* Sticky header */}
      {stickyHeader && (
        <PageStickyBar
          className="px-6"
          leading={
            <button
              type="button"
              onClick={onBack}
              className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full text-muted-foreground transition-colors hover:bg-secondary hover:text-foreground"
              aria-label="Back"
            >
              <ArrowLeft className="h-4 w-4" />
            </button>
          }
          title={<span className="text-sm font-semibold text-foreground">{location.name}</span>}
          trailing={
            fiction ? (
              <Badge
                className="text-[11px] border-0"
                style={{ backgroundColor: DEFAULT_FICTION_ACCENT, color: "#fff" }}
              >
                {fiction.title}
              </Badge>
            ) : null
          }
        />
      )}

      {/* Hero */}
      <div ref={heroRef} className="relative h-64 shrink-0 overflow-hidden md:h-80">
        <Image
          src={location.image}
          alt={location.name}
          fill
          className="object-cover"
          priority
          loading="eager"
          sizes="100vw"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-background via-background/50 to-transparent" />
        <div className="absolute inset-0 bg-gradient-to-r from-background/60 to-transparent" />

        {/* Back button */}
        <button
          onClick={onBack}
          className="absolute left-5 top-5 z-10 flex h-9 w-9 items-center justify-center rounded-full bg-background/60 text-foreground backdrop-blur-sm transition-colors hover:bg-background/80"
          aria-label="Back"
        >
          <ArrowLeft className="h-4 w-4" />
        </button>
      </div>

      {/* Content */}
      <div className="px-6 pb-16 pt-0 md:px-8">
        {/* Location meta */}
        <div className="flex flex-col gap-3">
          {fiction && (
            <div className="flex items-center gap-2">
              <Badge
                className="text-xs border-0"
                style={{ backgroundColor: DEFAULT_FICTION_ACCENT + "33", color: DEFAULT_FICTION_ACCENT }}
              >
                {fiction.type === "tv-series" ? (
                  <Tv className="mr-1 h-3 w-3" />
                ) : (
                  <Film className="mr-1 h-3 w-3" />
                )}
                {fiction.title}
              </Badge>
              <span className="text-xs text-muted-foreground">{fiction.year}</span>
            </div>
          )}

          <h1 className="text-2xl font-bold leading-tight text-foreground text-balance md:text-3xl">
            {location.name}
          </h1>

          <div className="flex items-center gap-1.5 text-muted-foreground">
            <MapPin className="h-3.5 w-3.5 shrink-0" />
            <span className="text-xs">{location.address}</span>
            {city && (
              <>
                <span className="text-xs opacity-40">&middot;</span>
                <span className="text-xs">{city.name}, {city.country}</span>
              </>
            )}
          </div>

          <p className="text-sm leading-relaxed text-muted-foreground">
            {location.description}
          </p>
        </div>

        {/* Visit Tip */}
        {location.visitTip && (
          <div className="mt-5 flex gap-3 rounded-xl border border-primary/20 bg-primary/5 px-4 py-3">
            <Lightbulb className="mt-0.5 h-4 w-4 shrink-0 text-primary" />
            <div>
              <p className="mb-1 text-xs font-semibold uppercase tracking-wider text-primary">
                Visitor Tip
              </p>
              <p className="text-sm leading-relaxed text-muted-foreground">
                {location.visitTip}
              </p>
            </div>
          </div>
        )}

        {/* Divider */}
        <div className="my-7 h-px bg-border/40" />

        {/* Scenes section — Netflix-style */}
        <div className="flex flex-col gap-5">
          <div className="flex items-center justify-between gap-4">
            <h2 className="text-lg font-bold text-foreground">
              {isTvSeries ? "Episodes filmed here" : "Scenes filmed here"}
            </h2>
            <div className="flex items-center gap-3">
              <span className="text-xs text-muted-foreground">
                {scenes.length} scene{scenes.length !== 1 ? "s" : ""}
              </span>
              <div className="flex items-center rounded-full border border-border/60 bg-secondary/30 p-1 text-[11px]">
                <button
                  onClick={() => setSceneView("detail")}
                  className={`px-3 py-1 rounded-full font-semibold transition-colors ${
                    sceneView === "detail"
                      ? "bg-primary text-primary-foreground"
                      : "text-muted-foreground hover:text-foreground"
                  }`}
                >
                  Details
                </button>
                <button
                  onClick={() => setSceneView("video")}
                  className={`px-3 py-1 rounded-full font-semibold transition-colors ${
                    sceneView === "video"
                      ? "bg-primary text-primary-foreground"
                      : "text-muted-foreground hover:text-foreground"
                  }`}
                >
                  Video
                </button>
              </div>
            </div>
          </div>

          {/* Season selector (TV only) */}
          {isTvSeries && seasons.length > 1 && (
            <div className="flex gap-2 overflow-x-auto pb-1 no-scrollbar">
              {seasons.map(([seasonNum, seasonScenes]) => (
                <button
                  key={seasonNum}
                  onClick={() => setSelectedSeason(seasonNum)}
                  className={`shrink-0 rounded-full px-4 py-1.5 text-xs font-semibold transition-colors ${
                    selectedSeason === seasonNum
                      ? "bg-primary text-primary-foreground"
                      : "bg-secondary text-muted-foreground hover:text-foreground"
                  }`}
                >
                  Season {seasonNum}
                  <span className="ml-1.5 opacity-60">({seasonScenes.length})</span>
                </button>
              ))}
            </div>
          )}

          {/* Scene list */}
          {displayedScenes.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-12 text-center">
              <Film className="mb-3 h-8 w-8 text-muted-foreground/40" />
              <p className="text-sm text-muted-foreground">No scenes recorded yet</p>
            </div>
          ) : sceneView === "detail" ? (
            <div className="flex flex-col gap-3">
              {displayedScenes.map((scene) => (
                <button
                  key={scene.id}
                  type="button"
                  onClick={() => setWatchSceneId(scene.id)}
                  className="overflow-hidden rounded-xl border border-border bg-card transition-colors"
                >
                  <div className="flex w-full items-stretch gap-5 p-4 text-left">
                    {/* Thumbnail */}
                    <div className="relative w-[200px] min-h-[120px] shrink-0 overflow-hidden rounded-lg self-stretch">
                      <Image
                        src={scene.thumbnail || "/placeholder.svg"}
                        alt={scene.title}
                        fill
                        className="object-cover"
                        sizes="180px"
                      />
                      <div className="absolute inset-0 flex items-center justify-center bg-black/30 opacity-0 transition-opacity hover:opacity-100">
                        <Play className="h-5 w-5 text-foreground" />
                      </div>
                      {scene.timestamp && (
                        <span className="absolute bottom-1 right-1 rounded bg-black/70 px-1 py-0.5 text-[10px] font-medium text-white">
                          {scene.timestamp}
                        </span>
                      )}
                    </div>

                    {/* Info */}
                    <div className="flex flex-1 flex-col gap-1 min-w-0">
