    </div>
  )
}

"use client"

import { useRef, useState, useEffect, useCallback } from "react"
import { ChevronLeft, ChevronRight, Images, X } from "lucide-react"
import { useTranslations } from "next-intl"
import type { Location } from "@/src/locations/domain/location.entity"
import Image from "next/image"
import { cn } from "@/lib/utils"
import { useIsMobile } from "@/hooks/use-mobile"
import { usePlaceSelectorCollapsedStorage } from "@/lib/local-storage-service-hooks"

/** Match nav map small height (SIZE_SMALL.height in nav-map.tsx) */
const CAROUSEL_HEIGHT = 140
const THUMB_SIZE = CAROUSEL_HEIGHT - 16 // minus py-2
const THUMB_SIZE_PX = `${THUMB_SIZE}px`

interface ThumbnailCarouselProps {
  locations: Location[]
  selectedLocationId?: string | null
  onLocationClick: (location: Location) => void
  /** When provided (e.g. from map page), parent owns state for Enter/Escape handling. */
  placeSelectorCollapsed?: boolean
  setPlaceSelectorCollapsed?: (collapsed: boolean) => void
}

export function ThumbnailCarousel({
  locations,
  selectedLocationId,
  onLocationClick,
  placeSelectorCollapsed: controlledCollapsed,
  setPlaceSelectorCollapsed: setControlledCollapsed,
}: ThumbnailCarouselProps) {
  const t = useTranslations("Map")
  const isMobile = useIsMobile()
  const scrollRef = useRef<HTMLDivElement>(null)
  const expandButtonRef = useRef<HTMLButtonElement>(null)
  const thumbRefs = useRef<(HTMLButtonElement | null)[]>([])
  const prevCollapsedRef = useRef<boolean | null>(null)

  const [internalCollapsed, setInternalCollapsed] = usePlaceSelectorCollapsedStorage()
  const placeSelectorCollapsed = controlledCollapsed ?? internalCollapsed
  const setPlaceSelectorCollapsed = setControlledCollapsed ?? setInternalCollapsed

  const [hoveredId, setHoveredId] = useState<string | null>(null)
  const isVisible = isMobile ? false : !placeSelectorCollapsed

  const selectedIndex =
    selectedLocationId != null
      ? locations.findIndex((loc) => loc.id === selectedLocationId)
      : -1
  const effectiveIndex = selectedIndex >= 0 ? selectedIndex : 0
  const selectedLocation = selectedIndex >= 0 ? locations[selectedIndex] : null

  const goToPrevPlace = useCallback(() => {
    if (locations.length === 0) return
    const nextIndex = selectedIndex > 0 ? selectedIndex - 1 : locations.length - 1
    onLocationClick(locations[nextIndex])
    thumbRefs.current[nextIndex]?.focus()
  }, [locations, selectedIndex, onLocationClick])

  const goToNextPlace = useCallback(() => {
    if (locations.length === 0) return
    const nextIndex =
      selectedIndex >= 0 && selectedIndex < locations.length - 1 ? selectedIndex + 1 : 0
    onLocationClick(locations[nextIndex])
    thumbRefs.current[nextIndex]?.focus()
  }, [locations, selectedIndex, onLocationClick])

  useEffect(() => {
    if (effectiveIndex < 0 || !scrollRef.current || !locations[effectiveIndex]) return
    const id = locations[effectiveIndex].id
    const thumb = scrollRef.current.querySelector(`[data-location-id="${id}"]`)
    if (thumb) {
      thumb.scrollIntoView({ behavior: "smooth", block: "nearest", inline: "center" })
    }
  }, [effectiveIndex, locations])

  // Focus expand button when transitioning from expanded to collapsed
  useEffect(() => {
    const wasExpanded = prevCollapsedRef.current === false
    const isNowCollapsed = placeSelectorCollapsed === true
    prevCollapsedRef.current = placeSelectorCollapsed
    if (wasExpanded && isNowCollapsed) {
      expandButtonRef.current?.focus()
    }
  }, [placeSelectorCollapsed])

  // When opening Navigation mode, focus the current or first thumb and sync map to that place
  useEffect(() => {
    if (!isVisible || locations.length === 0) return
    const loc = locations[effectiveIndex]
    if (loc) onLocationClick(loc)
    const toFocus = thumbRefs.current[effectiveIndex] ?? thumbRefs.current[0]
    toFocus?.focus()
  }, [isVisible]) // eslint-disable-line react-hooks/exhaustive-deps -- only on open

  const handleStripKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "ArrowLeft") {
      e.preventDefault()
      goToPrevPlace()
    } else if (e.key === "ArrowRight") {
      e.preventDefault()
      goToNextPlace()
    }
  }

  const handleClose = () => {
    setPlaceSelectorCollapsed(true)
  }

  if (locations.length === 0) return null

  if (!isVisible) {
    return (
      <div className="absolute bottom-4 left-1/2 z-[1000] flex -translate-x-1/2 items-end pointer-events-none md:left-4 md:translate-x-0">
        <button
          ref={expandButtonRef}
          type="button"
          onClick={() => setPlaceSelectorCollapsed(false)}
          className="pointer-events-auto flex items-center gap-2 rounded-lg border border-border bg-chrome/95 px-3 py-2 text-xs font-medium text-foreground shadow-[0_2px_8px_rgba(0,0,0,0.2)] backdrop-blur-sm transition-colors hover:bg-chrome"
          aria-label={t("navigationMode")}
        >
          <Images className="h-4 w-4" />
          {t("navigationMode")}
        </button>
      </div>
    )
  }

  return (
    <div className="absolute bottom-4 left-1/2 z-[1000] flex -translate-x-1/2 flex-col items-start gap-1 pointer-events-none md:left-4 md:translate-x-0">
      <button
        type="button"
        onClick={handleClose}
        className="pointer-events-auto flex h-8 w-8 shrink-0 items-center justify-center rounded-lg border border-border bg-chrome/95 text-foreground shadow-[0_2px_8px_rgba(0,0,0,0.2)] backdrop-blur-sm transition-colors hover:bg-chrome"
        aria-label={t("exitNavigationMode")}
      >
        <X className="h-4 w-4" />
      </button>
      <div
        className="pointer-events-auto flex flex-col rounded-lg overflow-hidden border border-border bg-card shadow-lg"
        style={{ height: CAROUSEL_HEIGHT, width: "min(700px, calc(100vw - 2rem))" }}
      >
        <div
          className="flex h-full items-center gap-1.5 px-2 py-2 bg-muted/50"
          onKeyDown={handleStripKeyDown}
          role="group"
          aria-label={t("navigationMode")}
        >
          <button
            onClick={goToPrevPlace}
            className="flex w-8 shrink-0 items-center justify-center rounded border border-border bg-background text-muted-foreground transition-colors hover:bg-muted hover:text-foreground"
            style={{ height: THUMB_SIZE }}
            aria-label={t("previousPlace")}
          >
            <ChevronLeft className="h-3 w-3" />
          </button>

          <div
            ref={scrollRef}
            className="flex flex-1 min-w-0 gap-1.5 overflow-x-auto scroll-smooth no-scrollbar py-0.5"
            role="listbox"
            aria-activedescendant={locations[effectiveIndex]?.id}
          >
            {locations.map((loc, index) => {
              const isSelected = selectedLocationId === loc.id
              const isHovered = hoveredId === loc.id
              const tabIndex = effectiveIndex === index ? 0 : -1
              return (
                <button
                  key={loc.id}
                  ref={(el) => {
                    thumbRefs.current[index] = el
                  }}
                  data-location-id={loc.id}
                  role="option"
                  tabIndex={tabIndex}
                  id={loc.id}
                  aria-selected={isSelected}
                  aria-label={t("placeOfTotal", {
                    name: loc.name,
                    current: index + 1,
                    total: locations.length,
                  })}
                  onClick={() => onLocationClick(loc)}
                  onMouseEnter={() => setHoveredId(loc.id)}
                  onMouseLeave={() => setHoveredId(null)}
                  onKeyDown={handleStripKeyDown}
                  className={cn(
                    "relative shrink-0 overflow-hidden rounded-sm border-2 transition-all duration-200 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background",
                    "inline-flex items-center justify-center",
                    "bg-muted border-border",
                    isSelected
                      ? "border-primary ring-2 ring-primary/30 ring-offset-2 ring-offset-background"
                      : isHovered
                        ? "border-border bg-muted"
                        : "opacity-90 hover:opacity-100 hover:border-border hover:bg-muted",
                  )}
                  style={{ width: THUMB_SIZE_PX, height: THUMB_SIZE_PX }}
                >
                  <Image
                    src={loc.image}
                    alt=""
                    fill
                    className="object-cover"
                    sizes={`${THUMB_SIZE}px`}
                  />
                </button>
              )
            })}
          </div>

          <button
            onClick={goToNextPlace}
            className="flex w-8 shrink-0 items-center justify-center rounded border border-border bg-background text-muted-foreground transition-colors hover:bg-muted hover:text-foreground"
            style={{ height: THUMB_SIZE }}
            aria-label={t("nextPlace")}
          >
            <ChevronRight className="h-3 w-3" />
          </button>
        </div>
      </div>
    </div>
  )
}

"use client"

import { useCallback, useEffect, useState } from "react"
import Image from "next/image"
import { Globe } from "lucide-react"
import { useTranslations } from "next-intl"
import { useRouter } from "@/i18n/navigation"
import { Button } from "@/components/ui/button"
import { MAPBOX_ACCESS_TOKEN } from "@/lib/map/mapbox/styles"
import { DEFAULT_FICTION_COVER } from "@/lib/constants/placeholders"
import {
  getUserCityCheckinsAction,
  getUserPlaceCheckinsEnrichedAction,
  type EnrichedPlaceCheckin,
} from "@/src/checkins/infrastructure/next/checkin.actions"
import type { CityCheckin } from "@/src/checkins/infrastructure/next/checkin.actions"
import type { City } from "@/src/cities/domain/city.entity"
import {
  PlacesSidebarRow,
  PROFILE_SEE_ALL_THRESHOLD,
  SidebarCard,
  SidebarSectionLoading,
} from "./profile-sidebar-sections"
type UnifiedCheckin =
  | { kind: "city"; data: CityCheckin; cityName: string; country: string }
  | { kind: "place"; data: EnrichedPlaceCheckin }

interface CheckinsListProps {
  /** Collapsed preview length when total exceeds `PROFILE_SEE_ALL_THRESHOLD`. Defaults to that threshold. */
  limit?: number
  cityMap?: Map<string, City>
  cityCheckins?: CityCheckin[]
  placeCheckins?: EnrichedPlaceCheckin[]
}

function cityCheckinMapUrl(lat: number, lng: number): string | null {
  if (!MAPBOX_ACCESS_TOKEN) return null
  return `https://api.mapbox.com/styles/v1/mapbox/streets-v12/static/pin-s+ef4444(${lng},${lat})/${lng},${lat},11,0/88x88@2x?access_token=${MAPBOX_ACCESS_TOKEN}&logo=false&attribution=false`
}

function placeCheckinThumbUrl(c: EnrichedPlaceCheckin): string {
  return c.placeImage?.trim() || c.fictionCover?.trim() || DEFAULT_FICTION_COVER
}

export function CheckinsList({
  limit = PROFILE_SEE_ALL_THRESHOLD,
  cityMap: externalCityMap,
  cityCheckins: externalCityCheckins,
  placeCheckins: externalPlaceCheckins,
}: CheckinsListProps) {
  const t = useTranslations("Checkins")
  const tProfile = useTranslations("Profile")
  const router = useRouter()

  const [cityCheckins, setCityCheckins] = useState<CityCheckin[]>(externalCityCheckins ?? [])
  const [placeCheckins, setPlaceCheckins] = useState<EnrichedPlaceCheckin[]>(externalPlaceCheckins ?? [])
  const [cities, setCities] = useState<Map<string, City>>(externalCityMap ?? new Map())
  const [loading, setLoading] = useState(!externalCityCheckins && !externalPlaceCheckins)
  const [showAll, setShowAll] = useState(false)

  const relativeDate = useCallback(
    (iso: string): string => {
      const d = new Date(iso)
      const now = new Date()
      const diffMs = now.getTime() - d.getTime()
      const diffDays = Math.floor(diffMs / 86400000)

      if (diffDays === 0) return t("today")
      if (diffDays === 1) return t("yesterday")
      if (diffDays < 7) return t("daysAgo", { days: diffDays })

      return d.toLocaleDateString(undefined, { day: "numeric", month: "short" })
    },
    [t],
  )

  const fetchData = useCallback(async () => {
    if (externalCityCheckins !== undefined && externalPlaceCheckins !== undefined) return
    setLoading(true)
    const [cityRes, placeRes] = await Promise.all([
      externalCityCheckins !== undefined ? null : getUserCityCheckinsAction(),
      externalPlaceCheckins !== undefined ? null : getUserPlaceCheckinsEnrichedAction(),
    ])
    if (cityRes?.data) setCityCheckins(cityRes.data)
    if (placeRes?.data) setPlaceCheckins(placeRes.data)
    setLoading(false)
  }, [externalCityCheckins, externalPlaceCheckins])

  useEffect(() => {
    if (externalCityCheckins !== undefined) setCityCheckins(externalCityCheckins)
  }, [externalCityCheckins])

  useEffect(() => {
    if (externalPlaceCheckins !== undefined) setPlaceCheckins(externalPlaceCheckins)
  }, [externalPlaceCheckins])

  useEffect(() => {
    if (externalCityMap !== undefined) setCities(externalCityMap)
  }, [externalCityMap])

  useEffect(() => {
    fetchData()
  }, [fetchData])

  const unified: UnifiedCheckin[] = [
    ...cityCheckins.map((c) => {
      const city = cities.get(c.cityId)
      return {
        kind: "city" as const,
        data: c,
        cityName: city?.name ?? c.cityId,
        country: city?.country ?? "",
        sortKey: c.checkedAt,
      }
    }),
    ...placeCheckins.map((c) => ({
      kind: "place" as const,
      data: c,
      sortKey: c.checkedAt,
    })),
  ]
    .sort((a, b) => b.sortKey.localeCompare(a.sortKey))
    .map(({ sortKey: _s, ...rest }) => rest as UnifiedCheckin)

  const showSeeAll = unified.length > PROFILE_SEE_ALL_THRESHOLD
  const visible =
    !showSeeAll
      ? unified
      : showAll
        ? unified
        : unified.slice(0, limit)
  const hasMore = showSeeAll

  if (loading) {
    return (
      <SidebarSectionLoading title={tProfile("checkIns")} message={t("loadingCheckins")} />
    )
  }

  return (
    <>
      <SidebarCard
        title={tProfile("checkIns")}
        ctaLabel={showSeeAll ? tProfile("seeAll") : undefined}
        emptyMessage={unified.length === 0 ? t("noCheckins") : undefined}
      >
        {unified.length === 0
          ? null
          : visible.map((item) => {
              if (item.kind === "city") {
                const c = item.data
                const city = cities.get(c.cityId)
                const mapUrl =
                  city && Number.isFinite(city.lat) && Number.isFinite(city.lng)
                    ? cityCheckinMapUrl(city.lat, city.lng)
                    : null
                const when = relativeDate(c.checkedAt)
                const subtitle = [
                  t("cityCheckinLabel"),
                  item.country || undefined,
                  when,
                ]
                  .filter(Boolean)
                  .join(" · ")

                return (
                  <PlacesSidebarRow
                    key={`city-${c.id}`}
                    title={item.cityName}
                    subtitle={subtitle}
                    leading={
                      mapUrl ? (
                        <Image
                          src={mapUrl}
                          alt=""
                          fill
                          sizes="40px"
                          className="object-cover"
                          unoptimized
                        />
                      ) : (
                        <span className="flex h-full w-full items-center justify-center">
                          <Globe className="h-5 w-5 text-muted-foreground" aria-hidden />
                        </span>
                      )
                    }
                  />
                )
              }

              const c = item.data
              const when = relativeDate(c.checkedAt)
              const subtitleParts = [c.fictionTitle, c.placeAddress, when].filter(Boolean)
              return (
                <button
                  key={`place-${c.id}`}
                  type="button"
                  onClick={() =>
                    router.push(
                      `/fiction/${encodeURIComponent(c.fictionId)}/place/${encodeURIComponent(c.placeId)}`,
                    )
                  }
                  className="block w-full text-left transition-colors hover:bg-muted/30"
                >
                  <PlacesSidebarRow
                    title={c.placeName}
                    subtitle={subtitleParts.join(" · ")}
                    leading={
                      <Image
                        src={placeCheckinThumbUrl(c)}
                        alt=""
                        fill
                        sizes="40px"
                        className="object-cover"
                      />
                    }
                  />
                </button>
              )
            })}
      </SidebarCard>
      {hasMore && unified.length > 0 && (
        <Button
          type="button"
          variant="ghost"
          size="sm"
          className="h-8 w-full text-xs font-medium text-muted-foreground hover:text-foreground"
          onClick={() => setShowAll((p) => !p)}
        >
          {showAll ? t("showLess") : t("showAll")}
        </Button>
      )}
    </>
  )
}

"use client"

import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
  type ReactNode,
} from "react"
import { getUserHomesAction } from "@/src/homes/infrastructure/next/home.actions"
import type { UserHome } from "@/src/homes/domain/home.entity"
import type { City } from "@/src/cities/domain/city.entity"

type HomesContextValue = {
  homes: UserHome[]
  cityMap: Map<string, City>
  loading: boolean
  error: string | null
  refetch: () => Promise<void>
  refreshCities: () => void
}

const HomesContext = createContext<HomesContextValue | null>(null)

export function HomesProvider({
  children,
  initialHomes,
  initialCities,
}: {
  children: ReactNode
  initialHomes?: UserHome[]
  initialCities?: City[]
}) {
  const [homes, setHomes] = useState<UserHome[]>(() => initialHomes ?? [])
  const [cityMap, setCityMap] = useState<Map<string, City>>(() =>
    initialCities?.length ? new Map(initialCities.map((c) => [c.id, c])) : new Map()
  )
  const [loading, setLoading] = useState(initialHomes === undefined)
  const [error, setError] = useState<string | null>(null)

  const refreshCities = useCallback(() => {
    // cities are provided via initialCities prop; no client-side refetch needed
  }, [])

  const refetch = useCallback(async () => {
    setError(null)
    const result = await getUserHomesAction()
    if (result.data) {
      setHomes(result.data)
    } else if (result.error) {
      setError(result.error)
    }
    setLoading(false)
  }, [])

  useEffect(() => {
    if (initialHomes === undefined) {
      refetch()
    } else {
      setLoading(false)
    }
    if (!initialCities?.length) refreshCities()
  }, [refetch, refreshCities, initialHomes, initialCities?.length])

  const value = useMemo(
    () => ({ homes, cityMap, loading, error, refetch, refreshCities }),
    [homes, cityMap, loading, error, refetch, refreshCities],
  )

  return <HomesContext.Provider value={value}>{children}</HomesContext.Provider>
}

export function useHomes() {
  const ctx = useContext(HomesContext)
  if (!ctx) {
    throw new Error("useHomes must be used within HomesProvider")
  }
  return ctx
}

