  }, [state])

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: 'DISMISS_TOAST', toastId }),
  }
}

export { useToast, toast }

import { createClient } from "@/lib/supabase/server"
import type { AuthUser, AuthResult, SignInCredentials, SignUpCredentials } from "./auth.types"

export async function signIn(credentials: SignInCredentials): Promise<AuthResult<AuthUser>> {
  const supabase = await createClient()
  const { data, error } = await supabase.auth.signInWithPassword(credentials)

  if (error) return { data: null, error: error.message }
  if (!data.user) return { data: null, error: "No user returned" }

  // Debug: inspect Supabase user metadata to verify display_name/full_name
  // This logs on the server where the auth call runs.
  // eslint-disable-next-line no-console
  console.log("[auth.supabase] signIn user_metadata:", data.user.user_metadata)

  const meta = data.user.user_metadata
  const display_name = (meta?.display_name as string | undefined) ?? null
  const full_name = (meta?.full_name as string | undefined) ?? null
  return {
    data: {
      id: data.user.id,
      email: data.user.email ?? "",
      display_name: display_name || full_name,
      full_name: full_name ?? null,
    },
    error: null,
  }
}

export async function signUp(credentials: SignUpCredentials): Promise<AuthResult<AuthUser>> {
  const supabase = await createClient()
  const { data, error } = await supabase.auth.signUp({
    email: credentials.email,
    password: credentials.password,
    options: {
      data:
        credentials.full_name
          ? {
              full_name: credentials.full_name,
              display_name: credentials.full_name,
            }
          : undefined,
    },
  })

  if (error) return { data: null, error: error.message }
  if (!data.user) return { data: null, error: "No user returned" }

  // If email confirmation is required, Supabase creates the user but doesn't start a session.
  // In that case we should NOT log the user in — surface a clear message instead.
  if (!data.session) {
    return {
      data: null,
      error: "We created your account! Check your email to verify it before logging in.",
    }
  }

  const meta = data.user.user_metadata
  const display_name = (meta?.display_name as string | undefined) ?? null
  const full_name = (meta?.full_name as string | undefined) ?? null
  return {
    data: {
      id: data.user.id,
      email: data.user.email ?? "",
      display_name: display_name || full_name,
      full_name: full_name ?? null,
    },
    error: null,
  }
}

export async function signOut(): Promise<AuthResult> {
  const supabase = await createClient()
  const { error } = await supabase.auth.signOut()

  return { data: null, error: error?.message ?? null }
}

export async function getUser(): Promise<AuthResult<AuthUser>> {
  const supabase = await createClient()
  const { data, error } = await supabase.auth.getUser()

  if (error || !data.user) return { data: null, error: error?.message ?? null }

  // Debug: inspect Supabase user metadata when restoring session
  // eslint-disable-next-line no-console
  console.log("[auth.supabase] getUser user_metadata:", data.user.user_metadata)

  const meta = data.user.user_metadata
  const display_name = (meta?.display_name as string | undefined) ?? null
  const full_name = (meta?.full_name as string | undefined) ?? null
  return {
    data: {
      id: data.user.id,
      email: data.user.email ?? "",
      display_name: display_name || full_name,
      full_name: full_name ?? null,
    },
    error: null,
  }
}

"use client"

import { useCallback, useEffect, useMemo, useRef, useState } from "react"
import { Marker, useMap } from "react-map-gl/mapbox"
import Supercluster from "supercluster"
import type { ClusterItem, ClusterLayerProps, LatLng } from "../types"

type PointFeature<T> = GeoJSON.Feature<GeoJSON.Point, T>
type ClusterFeature = Supercluster.ClusterFeature<Supercluster.AnyProps>

export function MapboxClusterLayer<T extends ClusterItem>({
  items,
  selectedItemId,
  onItemClick,
  renderItem,
  maxZoom = 20,
  radius = 70,
}: ClusterLayerProps<T>) {
  const maps = useMap()
  const mapRef = maps.current
  const [clusters, setClusters] = useState<
    Array<ClusterFeature | PointFeature<T>>
  >([])
  const [hoveredId, setHoveredId] = useState<string | null>(null)

  const supercluster = useMemo(() => {
    const sc = new Supercluster<T>({ maxZoom, radius })
    const points: Array<PointFeature<T>> = items.map((item) => ({
      type: "Feature" as const,
      geometry: {
        type: "Point" as const,
        coordinates: [item.position.lng, item.position.lat],
      },
      properties: item,
    }))
    sc.load(points)
    return sc
  }, [items, maxZoom, radius])

  const superclusterRef = useRef(supercluster)
  superclusterRef.current = supercluster

  const updateClusters = useCallback(() => {
    if (!mapRef) return
    try {
      const map = mapRef.getMap()
      const bounds = map.getBounds()
      if (!bounds) return
      const bbox: [number, number, number, number] = [
        bounds.getWest(),
        bounds.getSouth(),
        bounds.getEast(),
        bounds.getNorth(),
      ]
      const zoom = Math.floor(map.getZoom())
      setClusters(superclusterRef.current.getClusters(bbox, zoom))
    } catch {
      // Map not ready yet — skip this update
    }
  }, [mapRef])

  useEffect(() => {
    updateClusters()
  }, [updateClusters, supercluster])

  useEffect(() => {
    if (!mapRef) return
    try {
      const map = mapRef.getMap()
      const onMove = () => updateClusters()
      map.on("moveend", onMove)
      map.on("load", onMove)
      if (!map.isStyleLoaded()) {
        map.once("styledata", onMove)
      }
      return () => {
        map.off("moveend", onMove)
        map.off("load", onMove)
        map.off("styledata", onMove)
      }
    } catch {
      // Map not initialized yet
    }
  }, [mapRef, updateClusters])

  /** When items or clustering input changes, re-run after the next idle (valid bbox after fly/style). */
  useEffect(() => {
    if (!mapRef || items.length === 0) return
    try {
      const map = mapRef.getMap()
      const onIdle = () => updateClusters()
      map.once("idle", onIdle)
      return () => {
        map.off("idle", onIdle)
      }
    } catch {
      // Map not initialized yet
    }
  }, [mapRef, items.length, supercluster, updateClusters])

  return (
    <>
      {clusters.map((feature) => {
        const [lng, lat] = feature.geometry.coordinates
        const position: LatLng = { lat, lng }

        if ("cluster" in feature.properties && feature.properties.cluster) {
          const clusterId = feature.id as number
          const count = feature.properties.point_count as number
          let imageUrl = "/placeholder.jpg"
          try {
            const leaves = supercluster.getLeaves(clusterId, 1)
            imageUrl = leaves[0]?.properties?.imageUrl || "/placeholder.jpg"
          } catch {
            // Cluster ID can be stale if supercluster was recreated (e.g. items changed)
          }
          const dotSize = count >= 10 ? 20 : 18
          const dotFontSize = count >= 10 ? 10 : 11

          return (
            <Marker
              key={`cluster-${clusterId}`}
              longitude={lng}
              latitude={lat}
              anchor="bottom"
              onClick={(e) => {
                e.originalEvent.stopPropagation()
                if (!mapRef) return
                try {
                  const zoom = supercluster.getClusterExpansionZoom(clusterId)
                  mapRef.getMap().flyTo({ center: [lng, lat], zoom })
                } catch {
                  // Stale cluster id — just zoom in on the cluster center
                  const map = mapRef.getMap()
                  map.flyTo({
                    center: [lng, lat],
                    zoom: Math.min(map.getZoom() + 2, maxZoom),
                  })
                }
              }}
            >
              <div className="flex cursor-pointer flex-col items-center">
                <div className="relative overflow-visible">
                  <div
                    className="h-14 w-14 overflow-hidden rounded-lg border-2 border-border transition-all duration-200"
                    style={{ filter: "drop-shadow(0 4px 12px rgba(0,0,0,0.5))" }}
                  >
                    {/* eslint-disable-next-line @next/next/no-img-element */}
                    <img
                      src={imageUrl}
                      alt=""
                      className="h-full w-full object-cover"
                    />
                  </div>
                  <div
                    className="absolute flex items-center justify-center rounded-full bg-[#e8365d] font-bold text-white shadow-[0_2px_6px_rgba(0,0,0,0.4)] border-2 border-[#0b0f14]"
                    style={{
                      top: -Math.round(dotSize * 0.45),
                      right: -Math.round(dotSize * 0.45),
                      width: dotSize,
                      height: dotSize,
                      fontSize: dotFontSize,
                      lineHeight: 1,
                      zIndex: 10,
                    }}
                  >
                    {count}
                  </div>
                </div>
                <div className="h-0 w-0 border-l-[6px] border-r-[6px] border-t-[8px] border-l-transparent border-r-transparent border-t-border" />
              </div>
            </Marker>
          )
        }

        const item = feature.properties as T
        const isSelected = selectedItemId === item.id
        const isHovered = hoveredId === item.id

        return (
          <Marker
            key={item.id}
            longitude={lng}
            latitude={lat}
            anchor="bottom"
            onClick={
              onItemClick
                ? (e) => {
                    e.originalEvent.stopPropagation()
                    onItemClick(item)
                  }
                : undefined
            }
          >
            <div
              onMouseEnter={() => setHoveredId(item.id)}
              onMouseLeave={() => setHoveredId(null)}
            >
              {renderItem(item, { isSelected, isHovered })}
            </div>
          </Marker>
        )
      })}
    </>
  )
}

"use client"

import { useState, useCallback, useRef, useEffect } from "react"
import { motion, AnimatePresence } from "framer-motion"
import {
  Map as ReactMapGL,
  NavigationControl,
  FullscreenControl,
} from "react-map-gl/mapbox"
import "mapbox-gl/dist/mapbox-gl.css"
import type { Map as MapboxMap } from "mapbox-gl"
import type { MapContainerProps } from "../types"
import type { MapControlHandle } from "../types"
import { MapLoadedProvider } from "../map-loaded-context"
import { MAPBOX_ACCESS_TOKEN, MAPBOX_DAY_STYLE, MAPBOX_DAWN_STYLE, MAPBOX_DUSK_STYLE, MAPBOX_NIGHT_STYLE } from "./styles"
import { MapboxBuildings3D } from "./buildings"

export function MapboxContainer({
  id,
  defaultCenter,
  defaultZoom,
  center: controlledCenter,
  minZoom,
  maxZoom,
  interactive = true,
  colorScheme = "dark",
  mapStyle,
  className,
  children,
  onClick,
  onCenterChange,
  onMapReady,
  onZoomChange,
  controls,
}: MapContainerProps) {
  const [mapLoaded, setMapLoaded] = useState(false)
  const mapRef = useRef<MapboxMap | null>(null)
  const onLoad = useCallback(
    (e: { target: MapboxMap }) => {
      setMapLoaded(true)
      const map = e.target
      mapRef.current = map
      if (onMapReady) {
        const handle: MapControlHandle = {
          panTo: (pos) => map.panTo([pos.lng, pos.lat]),
          setZoom: (z) => map.setZoom(z),
          flyTo: (opts) => {
            try {
              map.flyTo({
                center: [opts.center.lng, opts.center.lat],
                zoom: opts.zoom ?? map.getZoom(),
                duration: opts.duration ?? 600,
                essential: true,
              })
              return true
            } catch {
              return false
            }
          },
          getCenter: () => {
            const c = map.getCenter()
            return { lat: c.lat, lng: c.lng }
          },
          setCenter: (pos) => map.setCenter([pos.lng, pos.lat]),
        }
        onMapReady(handle)
      }
    },
    [onMapReady],
  )

  // When center prop is provided (e.g. minimap), keep map view in sync with it
  useEffect(() => {
    if (!controlledCenter || !mapRef.current) return
    mapRef.current.setCenter([controlledCenter.lng, controlledCenter.lat])
  }, [controlledCenter?.lat, controlledCenter?.lng])

  /* 4 map styles: day, dawn, dusk, night — 1:1 with env vars (DAWN_URL→dawn, DUSK_URL→dusk) */
  const style = mapStyle
    ? mapStyle === "day"
      ? MAPBOX_DAY_STYLE
      : mapStyle === "dawn"
        ? MAPBOX_DAWN_STYLE
        : mapStyle === "dusk"
          ? MAPBOX_DUSK_STYLE
          : MAPBOX_NIGHT_STYLE
    : colorScheme === "light"
      ? MAPBOX_DAY_STYLE
      : MAPBOX_NIGHT_STYLE
  const showZoom = controls?.zoom ?? interactive
  const showFullscreen = controls?.fullscreen ?? false

  return (
    <div className={`${className} relative`} style={{ width: "100%", height: "100%" }}>
      <ReactMapGL
        id={id}
        initialViewState={{
          longitude: defaultCenter.lng,
          latitude: defaultCenter.lat,
          zoom: defaultZoom,
        }}
        minZoom={minZoom}
        maxZoom={maxZoom}
        mapStyle={style}
        mapboxAccessToken={MAPBOX_ACCESS_TOKEN}
        interactive={interactive}
        scrollZoom={interactive}
        dragPan={interactive}
        dragRotate={interactive}
        doubleClickZoom={interactive}
        touchZoomRotate={interactive}
        keyboard={interactive}
        onLoad={onLoad}
        onClick={
          onClick
            ? (e) => onClick({ lat: e.lngLat.lat, lng: e.lngLat.lng })
            : undefined
        }
        onMove={
          onCenterChange
            ? (e) =>
                onCenterChange({
                  lat: e.viewState.latitude,
                  lng: e.viewState.longitude,
                })
            : undefined
        }
        onMoveEnd={
          onCenterChange
            ? (e) =>
                onCenterChange({
                  lat: e.viewState.latitude,
                  lng: e.viewState.longitude,
                })
            : undefined
        }
        onZoomEnd={
          onZoomChange
            ? (e) => onZoomChange(Math.round(e.viewState.zoom))
            : undefined
        }
        style={{ width: "100%", height: "100%" }}
        attributionControl={false}
        logoPosition="bottom-right"
      >
        <MapLoadedProvider value={mapLoaded}>
          {showZoom && <NavigationControl showCompass={false} position="bottom-right" />}
          {showFullscreen && <FullscreenControl position="top-right" />}
          {children}
          {interactive && <MapboxBuildings3D />}
        </MapLoadedProvider>
      </ReactMapGL>
      <AnimatePresence>
        {!mapLoaded && (
          <motion.div
            className="absolute inset-0 z-10 flex items-center justify-center bg-background/80 backdrop-blur-[2px]"
            initial={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            transition={{ duration: 0.35, ease: "easeOut" }}
          >
            <motion.div
              className="flex flex-col items-center gap-3"
              initial={{ opacity: 0, y: 8 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.25 }}
            >
              <div className="h-9 w-9 rounded-full border-2 border-primary/40 border-t-primary animate-spin" />
              <span className="text-sm font-medium text-muted-foreground">Loading map…</span>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  )
}

"use client"

import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
} from "react"
import {
  type ThemeSettings,
  type ThemeBase,
  type StyleVariant,
  type ThemeMode,
  type TimeOfDay,
  THEME_STORAGE_KEY,
  defaultThemeSettings,
  getManualThemeClass,
  getRealtimeThemeClass,
  getTimeOfDayNow,
} from "./theme-settings"

export type MapStyleKey = "day" | "dawn" | "dusk" | "night"

type ThemeSettingsContextValue = {
  settings: ThemeSettings
  setBase: (base: ThemeBase) => void
  setStyleVariant: (v: StyleVariant) => void
  setMode: (mode: ThemeMode) => void
  /** Set manual theme in one go (mode=manual + base + styleVariant); saves and applies immediately */
  setManualStyle: (base: ThemeBase, styleVariant: StyleVariant) => void
  /** Apply and save full settings (e.g. from Settings page Save button); then navigate back */
  applyAndSave: (next: ThemeSettings) => void
  /** Current time of day when mode is realtime */
  timeOfDay: TimeOfDay | null
  /** Resolved theme base for UI (e.g. map): light vs dark */
  effectiveBase: ThemeBase
  /** Resolved map style for Mapbox: day, dawn, dusk, night */
  effectiveMapStyle: MapStyleKey
}

const ThemeSettingsContext = createContext<ThemeSettingsContextValue | null>(null)

function loadSettings(): ThemeSettings {
  if (typeof window === "undefined") return defaultThemeSettings
  try {
    const raw = localStorage.getItem(THEME_STORAGE_KEY)
    if (!raw) return defaultThemeSettings
    const parsed = JSON.parse(raw) as Partial<ThemeSettings>
    return {
      mode: parsed.mode ?? defaultThemeSettings.mode,
      base: parsed.base ?? defaultThemeSettings.base,
      styleVariant: parsed.styleVariant ?? defaultThemeSettings.styleVariant,
    }
  } catch {
    return defaultThemeSettings
  }
}

function saveSettings(settings: ThemeSettings) {
  try {
    localStorage.setItem(THEME_STORAGE_KEY, JSON.stringify(settings))
  } catch {
    // ignore
  }
}

function isDarkThemeClass(themeClass: string): boolean {
  return (
    themeClass.startsWith("theme-dark-") ||
    themeClass === "theme-realtime-evening" ||
    themeClass === "theme-realtime-night"
  )
}

/** Apply theme class to document. Dawn/dusk only affect the map; app UI always uses light or dark. */
function applyThemeToDocument(settings: ThemeSettings, timeOfDay: TimeOfDay | null) {
  const root = document.documentElement
  const existing = Array.from(root.classList).filter(
    (c) =>
      c.startsWith("theme-") &&
      (c.startsWith("theme-light-") ||
        c.startsWith("theme-dark-") ||
        c.startsWith("theme-realtime-"))
  )
  existing.forEach((c) => root.classList.remove(c))
  let themeClass: string
  if (settings.mode === "realtime") {
    const tod = timeOfDay ?? getTimeOfDayNow()
    themeClass = getRealtimeThemeClass(tod)
  } else {
    // Manual: only base (light/dark) affects app theme; styleVariant (day/dawn/dusk/night) affects map only
    themeClass = getManualThemeClass(settings.base, "1")
  }
  root.classList.add(themeClass)
  if (isDarkThemeClass(themeClass)) {
    root.classList.add("dark")
  } else {
    root.classList.remove("dark")
  }
}

export function ThemeSettingsProvider({ children }: { children: React.ReactNode }) {
  const [settings, setSettingsState] = useState<ThemeSettings>(defaultThemeSettings)
  const [timeOfDay, setTimeOfDay] = useState<TimeOfDay | null>(null)

  const setBase = useCallback((base: ThemeBase) => {
    setSettingsState((prev) => {
      const next = { ...prev, base }
      saveSettings(next)
      return next
    })
  }, [])

  const setStyleVariant = useCallback((styleVariant: StyleVariant) => {
    setSettingsState((prev) => {
      const next = { ...prev, styleVariant }
      saveSettings(next)
      return next
    })
  }, [])

  const setMode = useCallback((mode: ThemeMode) => {
    setSettingsState((prev) => {
      const next = { ...prev, mode }
      saveSettings(next)
      applyThemeToDocument(next, mode === "realtime" ? getTimeOfDayNow() : null)
      return next
    })
  }, [])

  const setManualStyle = useCallback((base: ThemeBase, styleVariant: StyleVariant) => {
    setSettingsState((prev) => {
      const next = { ...prev, mode: "manual" as const, base, styleVariant }
      saveSettings(next)
      applyThemeToDocument(next, null)
      return next
    })
  }, [])

  const applyAndSave = useCallback((next: ThemeSettings) => {
    saveSettings(next)
    applyThemeToDocument(next, next.mode === "realtime" ? getTimeOfDayNow() : null)
    setSettingsState(next)
  }, [])

  // Hydrate from localStorage and apply theme class to document
  useEffect(() => {
    setSettingsState(loadSettings())
  }, [])

  useEffect(() => {
    if (settings.mode === "realtime") {
      const tod = getTimeOfDayNow()
      setTimeOfDay(tod)
      applyThemeToDocument(settings, tod)
    } else {
      setTimeOfDay(null)
      applyThemeToDocument(settings, null)
    }
  }, [settings.mode, settings.base, settings.styleVariant, timeOfDay])

  // Realtime: update time of day every minute
  useEffect(() => {
    if (settings.mode !== "realtime") return
    const tick = () => setTimeOfDay(getTimeOfDayNow())
    const id = setInterval(tick, 60_000)
    return () => clearInterval(id)
  }, [settings.mode])

  const effectiveBase: ThemeBase = useMemo(() => {
    if (settings.mode === "manual") return settings.base
    const tod = timeOfDay ?? getTimeOfDayNow()
    return tod === "day" || tod === "afternoon" ? "light" : "dark"
  }, [settings.mode, settings.base, timeOfDay])

  const effectiveMapStyle: MapStyleKey = useMemo(() => {
    if (settings.mode === "manual") {
      if (settings.base === "light") return settings.styleVariant === "1" ? "day" : "dawn"
      return settings.styleVariant === "1" ? "night" : "dusk"
    }
    const tod = timeOfDay ?? getTimeOfDayNow()
    if (tod === "day") return "day"
    if (tod === "afternoon") return "dawn"
    if (tod === "evening") return "dusk"
    return "night"
  }, [settings.mode, settings.base, settings.styleVariant, timeOfDay])

  const value: ThemeSettingsContextValue = useMemo(
    () => ({
      settings,
      setBase,
      setStyleVariant,
      setMode,
      setManualStyle,
      applyAndSave,
      timeOfDay,
      effectiveBase,
      effectiveMapStyle,
    }),
    [settings, setBase, setStyleVariant, setMode, setManualStyle, applyAndSave, timeOfDay, effectiveBase, effectiveMapStyle]
  )

  return (
    <ThemeSettingsContext.Provider value={value}>
      {children}
    </ThemeSettingsContext.Provider>
  )
}

export function useThemeSettings() {
  const ctx = useContext(ThemeSettingsContext)
  if (!ctx) throw new Error("useThemeSettings must be used within ThemeSettingsProvider")
  return ctx
}

/** For map and other components that only need light/dark */
export function useThemeEffectiveBase(): ThemeBase {
  const ctx = useContext(ThemeSettingsContext)
  if (!ctx) return "dark"
  return ctx.effectiveBase
}

/** For map: returns day/dawn/dusk/night so the map can use the matching Mapbox style URL */
export function useMapStyle(): MapStyleKey {
  const ctx = useContext(ThemeSettingsContext)
  if (!ctx) return "night"
  return ctx.effectiveMapStyle
}

"use server"

import { cache } from "react"
import { getSessionUserId } from "@/lib/auth/auth.service"
import { checkinsSupabaseAdapter } from "@/src/checkins/infrastructure/supabase/checkin.repository.impl"
import { checkinCityUseCase } from "@/src/checkins/application/checkin-city.usecase"
import { checkinPlaceUseCase } from "@/src/checkins/application/checkin-place.usecase"
import { listMyCityCheckinsUseCase } from "@/src/checkins/application/list-my-city-checkins.usecase"
import type { CityCheckin, EnrichedPlaceCheckin, PlaceCheckin } from "@/src/checkins/domain/checkin.entity"
import type { CheckinResult } from "./checkin.actions.types"
import { loadEnrichedPlaceCheckinsForCurrentUser } from "./checkin.queries"

export type { CheckinResult } from "./checkin.actions.types"
export type { CityCheckin, EnrichedPlaceCheckin, PlaceCheckin } from "@/src/checkins/domain/checkin.entity"

export async function checkinCityAction(
  cityId: string,
  lat: number | null,
  lng: number | null,
  origin: "auto" | "manual",
): Promise<CheckinResult<CityCheckin>> {
  const userId = await getSessionUserId()
  if (!userId) return { data: null, error: "Unauthorized" }
  try {
    const checkin = await checkinCityUseCase(userId, cityId, lat, lng, origin, checkinsSupabaseAdapter)
    if (!checkin) return { data: null, error: "Failed to check in to city" }
    return { data: checkin, error: null }
  } catch (e) {
    return { data: null, error: e instanceof Error ? e.message : "Failed to check in to city" }
  }
}

async function fetchUserCityCheckinsAction(): Promise<CheckinResult<CityCheckin[]>> {
  const userId = await getSessionUserId()
  if (!userId) return { data: null, error: "Unauthorized" }
  try {
    const checkins = await listMyCityCheckinsUseCase(userId, checkinsSupabaseAdapter)
    return { data: checkins, error: null }
  } catch (e) {
    return { data: null, error: e instanceof Error ? e.message : "Failed to load city checkins" }
  }
}

/** Request-scoped dedupe for profile checkins reads. */
export const getUserCityCheckinsAction = cache(fetchUserCityCheckinsAction)

async function fetchUserPlaceCheckinsEnrichedAction(): Promise<CheckinResult<EnrichedPlaceCheckin[]>> {
  try {
    const data = await loadEnrichedPlaceCheckinsForCurrentUser()
    return { data, error: null }
  } catch (e) {
    return { data: null, error: e instanceof Error ? e.message : "Failed to load enriched place checkins" }
  }
}

/** Request-scoped dedupe for profile sidebar/list reads. */
export const getUserPlaceCheckinsEnrichedAction = cache(fetchUserPlaceCheckinsEnrichedAction)
